import React, { useState, useRef, useEffect } from 'react';
import { 
  Folder, 
  FileText, 
  MoreVertical, 
  Edit3, 
  Search, 
  Upload, 
  Plus,
  Eye,
  History,
  Filter,
  Calendar,
  Tag,
  ChevronDown,
  User,
  X,
  Check,
  ShieldAlert,
  ShieldCheck,
  Clock,
  ExternalLink,
  Code2,
  PackageOpen,
  ChevronRight,
  Loader2,
  Database,
  Workflow,
  Layout,
  Cpu,
  Grid3X3
} from 'lucide-react';
import { ResourceItem, ViewMode, Tab, ResourceType } from '../types';

interface MainContentProps {
  data: ResourceItem[];
  viewMode: ViewMode;
  activeTab?: Tab;
  onOpenTab: (item: ResourceItem) => void;
}

const FILTER_CATEGORIES = [
  { label: '页面展现', items: ['电子表格', 'UX'] },
  { label: '流程逻辑', items: ['工作流', 'python脚本'] },
  { label: '数据模型', items: ['财务模型', '维度', '领域模型'] },
  { label: '数据湖仓', items: ['关系数据库'] },
  { label: '数据集成', items: ['数据流', '连接器'] },
  { label: '基础服务', items: ['菜单', '变量', '权限方案', '值列表'] },
  { label: 'V2组件', items: ['页面', '图表', '清单表', '审批流', '业务模型'] },
  { label: '场景-财务工具', items: ['会计引擎'] },
];

const HISTORY_DATA = [
  { user: 'liuqing', action: '修改了资源', target: '0101 每日定时对账...', time: '10分钟前' },
  { user: 'Admin', action: '发布了新版本', target: '财务报表集成接口', time: '1小时前' },
  { user: 'liuqing', action: '删除了历史版本', target: '对账核销模型', time: '昨天 14:20' },
  { user: 'System', action: '自动备份完成', target: '全局数据仓库', time: '昨天 02:00' },
];

const getIconForType = (type: ResourceType) => {
  switch (type) {
    case 'folder': return <Folder size={16} className="text-amber-500 fill-amber-500/10" />;
    case 'model': return <Database size={16} className="text-purple-500" />;
    case 'logic': return <Workflow size={16} className="text-sky-500" />;
    case 'workflow': return <Cpu size={16} className="text-indigo-500" />;
    case 'spreadsheet': return <Grid3X3 size={16} className="text-emerald-500" />;
    case 'ux': return <Layout size={16} className="text-blue-500" />;
    default: return <FileText size={16} className="text-slate-400" />;
  }
};

const MainContent: React.FC<MainContentProps> = ({ data, viewMode, activeTab, onOpenTab }) => {
  const [isFilterOpen, setIsFilterOpen] = useState(false);
  const [isHistoryOpen, setIsHistoryOpen] = useState(false);
  const [activeFilters, setActiveFilters] = useState<string[]>([]);
  const [selectedUser, setSelectedUser] = useState<string>('all');
  const [timeRange, setTimeRange] = useState<string>('all');
  const [isRefreshing, setIsRefreshing] = useState(false);

  const historyRef = useRef<HTMLDivElement>(null);
  const filterRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (historyRef.current && !historyRef.current.contains(event.target as Node)) {
        setIsHistoryOpen(false);
      }
      if (filterRef.current && !filterRef.current.contains(event.target as Node)) {
        setIsFilterOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const toggleFilterItem = (item: string) => {
    setActiveFilters(prev => prev.includes(item) ? prev.filter(i => i !== item) : [...prev, item]);
  };

  const handleApplyFilters = () => {
    setIsRefreshing(true);
    // 这里不再关闭筛选器菜单
    setTimeout(() => {
      setIsRefreshing(false);
    }, 600);
  };

  if (!activeTab) return (
    <div className="flex-1 flex flex-col items-center justify-center h-full bg-slate-50 p-12 text-center">
      <div className="w-24 h-24 bg-slate-200/50 text-slate-400 rounded-full flex items-center justify-center mb-6 border-4 border-white shadow-sm">
        <PackageOpen size={48} strokeWidth={1.5} />
      </div>
      <h2 className="text-xl font-black text-slate-400 mb-2 uppercase tracking-widest">暂无活跃标签页</h2>
    </div>
  );

  const isPlaceholderTab = activeTab.id !== 'elements-view' && !activeTab.id.startsWith('module-') && activeTab.id !== 'default-home';

  if (isPlaceholderTab) {
    return (
      <div className="flex-1 flex flex-col items-center justify-center bg-slate-50 p-12 text-center h-full">
        <div className="w-20 h-20 bg-blue-100 text-blue-600 rounded-3xl flex items-center justify-center mb-6 shadow-xl shadow-blue-500/10"><Code2 size={40} /></div>
        <h2 className="text-2xl font-black text-slate-800 mb-2">{activeTab.title}</h2>
        <p className="text-slate-500 max-w-md">这是一个开发中的编辑器视图。您可以在此配置资源属性、编写脚本或设计界面。</p>
        <div className="mt-8 flex gap-3">
          <button className="px-6 py-2 bg-blue-600 text-white rounded-lg font-bold shadow-lg shadow-blue-600/20 hover:bg-blue-700 transition-all">开始编辑</button>
          <button className="px-6 py-2 bg-white border border-slate-200 text-slate-600 rounded-lg font-bold hover:bg-slate-50 transition-all">预览视图</button>
        </div>
      </div>
    );
  }

  return (
    <div className="flex-1 flex flex-col h-full bg-white relative">
      {/* List Toolbar */}
      <div className="h-14 border-b border-slate-100 flex items-center px-6 gap-4 bg-white shrink-0">
        <div className="flex-1 relative">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
          <input 
            type="text" 
            placeholder={`在 "${activeTab.title}" 中搜索...`}
            className="w-full bg-slate-50 border border-slate-200 rounded-lg py-2 pl-10 pr-4 text-[13px] outline-none focus:border-blue-500 focus:bg-white transition-all"
          />
        </div>

        <div className="flex items-center gap-2">
          <div className="relative" ref={filterRef}>
            <button 
              onClick={() => setIsFilterOpen(!isFilterOpen)}
              className={`flex items-center gap-2 px-3 py-2 rounded-lg border transition-all ${
                isFilterOpen || activeFilters.length > 0
                  ? 'bg-blue-50 border-blue-200 text-blue-600 shadow-sm' 
                  : 'bg-white border-slate-200 text-slate-600 hover:border-slate-300'
              }`}
            >
              <Filter size={16} />
              <span className="text-[13px] font-medium">筛选</span>
              {activeFilters.length > 0 && (
                <span className="bg-blue-600 text-white text-[10px] w-4 h-4 rounded-full flex items-center justify-center">{activeFilters.length}</span>
              )}
            </button>

            {isFilterOpen && (
              <div className="absolute right-0 top-full mt-2 w-[480px] bg-white border border-slate-200 rounded-xl shadow-2xl z-[100] p-5 animate-in fade-in zoom-in duration-150 origin-top-right">
                <div className="flex items-center justify-between mb-4">
                  <h3 className="text-[14px] font-bold text-slate-800">资源筛选</h3>
                  <button onClick={() => setIsFilterOpen(false)} className="text-slate-400 hover:text-slate-600"><X size={18} /></button>
                </div>

                <div className="grid grid-cols-2 gap-6">
                  <div className="space-y-4">
                    <div className="space-y-2">
                      <label className="text-[11px] font-black text-slate-400 uppercase tracking-widest">资源类型</label>
                      <div className="grid grid-cols-2 gap-1">
                        {FILTER_CATEGORIES.map(cat => (
                          <button 
                            key={cat.label}
                            onClick={() => toggleFilterItem(cat.label)}
                            className={`text-left px-2 py-1.5 rounded text-[12px] transition-colors ${
                              activeFilters.includes(cat.label) ? 'bg-blue-600 text-white' : 'hover:bg-slate-50 text-slate-600'
                            }`}
                          >
                            {cat.label}
                          </button>
                        ))}
                      </div>
                    </div>
                  </div>

                  <div className="space-y-4">
                    <div className="space-y-2">
                      <label className="text-[11px] font-black text-slate-400 uppercase tracking-widest">更新时间</label>
                      <div className="space-y-1">
                        {['全部时间', '最近24小时', '最近一周', '最近一个月'].map(time => (
                          <button 
                            key={time}
                            onClick={() => setTimeRange(time)}
                            className={`w-full text-left px-2 py-1.5 rounded text-[12px] transition-colors ${
                              timeRange === time ? 'bg-blue-50 text-blue-600 font-bold' : 'text-slate-600 hover:bg-slate-50'
                            }`}
                          >
                            {time}
                          </button>
                        ))}
                      </div>
                    </div>
                  </div>
                </div>

                <div className="mt-6 pt-4 border-t border-slate-100 flex justify-between items-center">
                  <button 
                    onClick={() => setActiveFilters([])}
                    className="text-[12px] text-slate-400 hover:text-slate-600 underline"
                  >
                    重置筛选条件
                  </button>
                  <div className="flex gap-2">
                    <button 
                      onClick={() => setIsFilterOpen(false)}
                      className="px-4 py-1.5 rounded-lg text-[12px] font-bold text-slate-500 hover:bg-slate-50"
                    >
                      取消
                    </button>
                    <button 
                      onClick={handleApplyFilters}
                      className="px-6 py-1.5 rounded-lg text-[12px] font-bold bg-blue-600 text-white shadow-lg shadow-blue-600/20 hover:bg-blue-700"
                    >
                      确定
                    </button>
                  </div>
                </div>
              </div>
            )}
          </div>

          <div className="relative" ref={historyRef}>
            <button 
              onClick={() => setIsHistoryOpen(!isHistoryOpen)}
              className="p-2 bg-white border border-slate-200 text-slate-600 rounded-lg hover:border-slate-300 transition-all"
            >
              <History size={18} />
            </button>
            {isHistoryOpen && (
              <div className="absolute right-0 top-full mt-2 w-72 bg-white border border-slate-200 rounded-xl shadow-2xl z-[100] overflow-hidden animate-in fade-in slide-in-from-top-2">
                <div className="p-3 border-b border-slate-50 bg-slate-50/50 flex items-center justify-between">
                  <span className="text-[11px] font-black text-slate-400 uppercase tracking-widest">操作审计</span>
                  <button className="text-[10px] text-blue-600 font-bold">查看全部</button>
                </div>
                <div className="max-h-[320px] overflow-y-auto no-scrollbar">
                  {HISTORY_DATA.map((h, i) => (
                    <div key={i} className="p-3 border-b border-slate-50 hover:bg-slate-50 transition-colors">
                      <div className="flex items-center gap-2 mb-1">
                        <div className="w-5 h-5 rounded-full bg-blue-100 text-blue-600 flex items-center justify-center text-[10px] font-bold">{h.user.charAt(0)}</div>
                        <span className="text-[11px] font-bold text-slate-700">{h.user}</span>
                        <span className="text-[10px] text-slate-400 ml-auto">{h.time}</span>
                      </div>
                      <div className="text-[11px] text-slate-600">{h.action} <span className="font-medium text-blue-600">{h.target}</span></div>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        </div>
      </div>

      {/* Main List Area */}
      <div className="flex-1 overflow-y-auto no-scrollbar relative p-6">
        {/* Loading Overlay */}
        {isRefreshing && (
          <div className="absolute inset-0 bg-white/60 z-50 flex items-center justify-center backdrop-blur-[2px] transition-all">
            <div className="flex flex-col items-center gap-3">
              <div className="p-3 bg-white rounded-2xl shadow-xl border border-slate-100">
                <Loader2 className="animate-spin text-blue-600" size={32} />
              </div>
              <span className="text-[12px] font-bold text-slate-400 uppercase tracking-widest animate-pulse">正在获取最新资源...</span>
            </div>
          </div>
        )}

        <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-4">
          {data.map((item) => (
            <div 
              key={item.id}
              onClick={() => onOpenTab(item)}
              className="group bg-white border border-slate-200 rounded-xl p-4 hover:border-blue-400 hover:shadow-xl hover:shadow-blue-600/5 transition-all cursor-pointer relative"
            >
              <div className="flex items-start justify-between mb-3">
                <div className={`p-2.5 rounded-xl bg-slate-50 group-hover:bg-blue-50 transition-colors shadow-sm`}>
                  {getIconForType(item.type)}
                </div>
                <button className="text-slate-300 hover:text-slate-600 opacity-0 group-hover:opacity-100 transition-all p-1">
                  <MoreVertical size={16} />
                </button>
              </div>

              <div className="space-y-1">
                <h3 className="font-bold text-slate-800 text-[14px] truncate leading-tight group-hover:text-blue-600 transition-colors">{item.name}</h3>
                <div className="flex items-center gap-2 text-[11px] font-mono text-slate-400">
                  <span>{item.code}</span>
                  <span className="w-1 h-1 rounded-full bg-slate-200"></span>
                  <span className="text-blue-500">{item.version}</span>
                </div>
              </div>

              <div className="mt-4 pt-4 border-t border-slate-50 flex items-center justify-between">
                <div className="flex items-center gap-1.5">
                  <div className="w-5 h-5 rounded-full bg-slate-100 text-slate-500 flex items-center justify-center text-[10px] font-bold">
                    {item.createdBy.charAt(0)}
                  </div>
                  <span className="text-[11px] text-slate-500">{item.createdBy}</span>
                </div>
                <div className="flex items-center gap-1 text-[10px] text-slate-400">
                  <Clock size={10} />
                  <span>{item.updatedAt.split(' ')[0]}</span>
                </div>
              </div>
            </div>
          ))}

          {/* New Resource Placeholder */}
          <button className="border-2 border-dashed border-slate-200 rounded-xl flex flex-col items-center justify-center p-6 text-slate-400 hover:border-blue-400 hover:text-blue-600 hover:bg-blue-50/30 transition-all group">
            <div className="w-10 h-10 rounded-full bg-slate-50 flex items-center justify-center mb-2 group-hover:scale-110 transition-transform">
              <Plus size={20} />
            </div>
            <span className="text-[13px] font-bold">新建资源</span>
          </button>
        </div>
      </div>

      {/* Footer Info */}
      <div className="h-8 bg-slate-50 border-t border-slate-100 px-6 flex items-center justify-between shrink-0">
        <div className="flex items-center gap-4 text-[10px] text-slate-400 font-medium">
          <div className="flex items-center gap-1.5"><Database size={12} /> <span>连接就绪: MainDB_Cluster</span></div>
          <div className="flex items-center gap-1.5"><ShieldCheck size={12} className="text-emerald-500" /> <span>安全级别: 核心受保护</span></div>
        </div>
        <div className="text-[10px] text-slate-400 font-mono">Environment: PRODUCTION | Region: CN-NORTH-1</div>
      </div>
    </div>
  );
};

export default MainContent;

import React, { useState, useRef, useEffect } from 'react';
import { 
  Folder, 
  FileText, 
  MoreVertical, 
  Edit3, 
  Search, 
  Upload, 
  Plus,
  Eye,
  History,
  Filter,
  Calendar,
  Tag,
  ChevronDown,
  User,
  X,
  Check,
  ShieldAlert,
  ShieldCheck,
  Clock,
  ExternalLink,
  Code2,
  PackageOpen,
  ChevronRight,
  Loader2
} from 'lucide-react';
import { ResourceItem, ViewMode, Tab } from '../types';

interface MainContentProps {
  data: ResourceItem[];
  viewMode: ViewMode;
  activeTab?: Tab;
  onOpenTab: (item: ResourceItem) => void;
}

const FILTER_CATEGORIES = [
  { label: '页面展现', items: ['电子表格', 'UX'] },
  { label: '流程逻辑', items: ['工作流', 'python脚本'] },
  { label: '数据模型', items: ['财务模型', '维度', '领域模型'] },
  { label: '数据湖仓', items: ['关系数据库'] },
  { label: '数据集成', items: ['数据流', '连接器'] },
  { label: '基础服务', items: ['菜单', '变量', '权限方案', '值列表'] },
  { label: 'V2组件', items: ['页面', '图表', '清单表', '审批流', '业务模型'] },
  { label: '场景-财务工具', items: ['会计引擎'] },
];

const HISTORY_DATA = [
  { user: 'liuqing', action: '修改了资源', target: '0101 每日定时对账...', time: '10分钟前' },
  { user: 'Admin', action: '发布了新版本', target: '财务报表集成接口', time: '1小时前' },
  { user: 'liuqing', action: '删除了历史版本', target: '对账核销模型', time: '昨天 14:20' },
  { user: 'System', action: '自动备份完成', target: '全局数据仓库', time: '昨天 02:00' },
];

const MainContent: React.FC<MainContentProps> = ({ data, viewMode, activeTab, onOpenTab }) => {
  const [isFilterOpen, setIsFilterOpen] = useState(false);
  const [isHistoryOpen, setIsHistoryOpen] = useState(false);
  const [activeFilters, setActiveFilters] = useState<string[]>([]);
  const [selectedUser, setSelectedUser] = useState<string>('all');
  const [timeRange, setTimeRange] = useState<string>('all');
  const [isRefreshing, setIsRefreshing] = useState(false);

  const historyRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (historyRef.current && !historyRef.current.contains(event.target as Node)) {
        setIsHistoryOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const toggleFilterItem = (item: string) => {
    setActiveFilters(prev => prev.includes(item) ? prev.filter(i => i !== item) : [...prev, item]);
  };

  const handleApplyFilters = () => {
    setIsRefreshing(true);
    // 模拟刷新效果，不关闭筛选器面板
    setTimeout(() => {
      setIsRefreshing(false);
    }, 600);
  };

  if (!activeTab) return (
    <div className="flex-1 flex flex-col items-center justify-center h-full bg-slate-50 p-12 text-center">
      <div className="w-24 h-24 bg-slate-200/50 text-slate-400 rounded-full flex items-center justify-center mb-6 border-4 border-white shadow-sm">
        <PackageOpen size={48} strokeWidth={1.5} />
      </div>
      <h2 className="text-xl font-black text-slate-400 mb-2 uppercase tracking-widest">暂无活跃标签页</h2>
    </div>
  );

  const isPlaceholderTab = activeTab.id !== 'elements-view' && !activeTab.id.startsWith('module-') && activeTab.id !== 'default-home';
  if (isPlaceholderTab) {
    return (
      <div className="flex-1 flex flex-col items-center justify-center bg-slate-50 p-12 text-center h-full">
        <div className="w-20 h-20 bg-blue-100 text-blue-600 rounded-3xl flex items-center justify-center mb-6 shadow-xl shadow-blue-500/10"><Code2 size={40} /></div>
        <h2 className="text-2xl font-black text-slate-800 mb-2">{activeTab.title}</h2>
        <p className="text-slate-400 max-w-sm">正在加载资源编辑器...</p>
      </div>
    );
  }

  return (
    <div className="flex flex-col h-full bg-[#f9fafb] relative overflow-hidden">
      {/* Top Action Toolbar */}
      <div className="px-6 py-4 flex items-center justify-between border-b border-slate-200 bg-white shrink-0 z-20">
        <div className="flex items-center gap-3">
          <button 
            onClick={() => setIsFilterOpen(!isFilterOpen)}
            className={`flex items-center gap-2 px-3 py-1.5 border rounded-lg text-[13px] font-medium transition-all ${
              isFilterOpen ? 'bg-blue-600 text-white border-blue-600 shadow-sm' : 'bg-white border-slate-200 text-slate-600 hover:bg-slate-50 shadow-sm'
            }`}
          >
            <Filter size={14} /> 筛选
          </button>
          <div className="relative group">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={14} />
            <input type="text" placeholder="搜索名称或描述..." className="w-72 border border-slate-200 rounded-lg py-1.5 pl-9 pr-3 text-[13px] focus:border-blue-500 outline-none bg-slate-50/50" />
          </div>
        </div>
        <div className="flex items-center gap-2">
          <button className="flex items-center gap-1.5 px-3 py-1.5 bg-white border border-slate-200 text-slate-600 rounded-lg text-[13px] font-medium hover:bg-slate-50"><Upload size={14} /> 导入</button>
          <button className="flex items-center gap-1.5 px-4 py-1.5 bg-blue-600 text-white rounded-lg text-[13px] font-bold hover:bg-blue-700 shadow-md active:scale-95 transition-transform"><Plus size={16} /> 新建元素</button>

          <div className="w-[1px] h-6 bg-slate-200 mx-2"></div>

          <div className="flex items-center gap-1">
            <button className="p-2 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-lg" title="权限设置">
              <ShieldCheck size={18} />
            </button>

            <div className="relative" ref={historyRef}>
              <button onClick={() => setIsHistoryOpen(!isHistoryOpen)} className={`p-2 rounded-lg transition-colors ${isHistoryOpen ? 'bg-blue-600 text-white shadow-sm' : 'text-slate-400 hover:text-blue-600 hover:bg-blue-50'}`} title="操作历史">
                <History size={18} />
              </button>
              {isHistoryOpen && (
                <div className="absolute right-0 top-full mt-2 w-80 bg-white rounded-xl shadow-2xl border border-slate-100 z-50 overflow-hidden animate-in fade-in zoom-in duration-150 origin-top-right">
                  <div className="p-3 border-b border-slate-50 bg-slate-50/50 flex items-center justify-between">
                    <span className="text-[11px] font-black text-slate-400 uppercase tracking-widest">操作历史</span>
                    <button className="text-[10px] font-bold text-blue-600 hover:text-blue-700 flex items-center gap-0.5">
                      查看更多 <ChevronRight size={10} />
                    </button>
                  </div>
                  <div className="p-1 max-h-[320px] overflow-y-auto no-scrollbar">
                    {HISTORY_DATA.map((h, i) => (
                      <div key={i} className="p-3 hover:bg-slate-50 rounded-lg border border-transparent hover:border-slate-100 transition-colors cursor-default">
                        <div className="flex justify-between items-start mb-1">
                          <span className="font-bold text-slate-700 text-[12px]">{h.user}</span>
                          <span className="text-[10px] text-slate-400 flex items-center gap-1 whitespace-nowrap"><Clock size={10} /> {h.time}</span>
                        </div>
                        <div className="text-[11px] text-slate-500 line-clamp-2 leading-relaxed">{h.action} <span className="text-blue-600 font-medium">{h.target}</span></div>
                      </div>
                    ))}
                  </div>
                </div>
              )}
            </div>
          </div>
        </div>
