  },
  {
    id: 'f2', name: '财务报表集成接口', code: 'CONN_FIN_REP', type: 'connector', description: '财务报表集成数据流核心连接器', version: 'v1.0.2', createdBy: 'liuqing', updatedAt: '2025-05-14 17:28:09',
  },
  {
