                    )) : <div className="p-3 text-[11px] text-slate-400 text-center italic">无匹配记录</div>}
                  </div>
                )}
              </div>

              <div className="px-1">
                <button 
                  onClick={() => toggleGroup('fav')}
                  className="w-full flex items-center justify-between p-1.5 mb-1 text-slate-400 bg-slate-50/50 rounded hover:bg-slate-100/50 transition-colors"
                >
                  <div className="flex items-center gap-2">
                    <Star size={14} className="text-amber-400" />
                    <span className="text-[11px] font-black uppercase tracking-widest">我的收藏</span>
                  </div>
                  {groupsExpanded.fav ? <ChevronDown size={12} /> : <ChevronRight size={12} />}
                </button>

                {groupsExpanded.fav && (
                  <div className="space-y-0.5 animate-in fade-in slide-in-from-top-1 duration-200">
                    {filteredFav.length > 0 ? filteredFav.map(item => (
                      <div key={item.id} onClick={() => onSelectResource(item)} className="flex items-center gap-2 p-1.5 rounded cursor-pointer hover:bg-blue-50/50 transition-colors group">
                        {getIconForType(item.type)}
                        <span className={`text-[12px] truncate flex-1 ${activeTab?.id === item.id ? 'text-blue-600 font-bold' : 'text-slate-500'}`}>{item.name}</span>
                        <button 
                          className="opacity-0 group-hover:opacity-100 p-1 text-amber-400 hover:text-slate-400 transition-all"
                          onClick={(e) => { e.stopPropagation(); /* 触发取消收藏逻辑 */ }}
                          title="取消收藏"
                        >
                          <Star size={12} fill="currentColor" />
                        </button>
                      </div>
                    )) : <div className="p-3 text-[11px] text-slate-400 text-center italic">无匹配收藏</div>}
                  </div>
                )}
              </div>
            </div>
          ) : (
            currentTree.map(dir => (
              <div key={dir.id} className="mb-0.5">
                <div onClick={() => toggleExpand(dir.id)} className="flex items-center gap-2 p-1.5 hover:bg-slate-100/60 rounded cursor-pointer group">
                  <div className="w-4 h-4 flex items-center justify-center shrink-0">
                    {expanded[dir.id] ? <ChevronDown size={12} className="text-slate-400" /> : <ChevronRight size={12} className="text-slate-400" />}
                  </div>
                  {getIconForType('folder')}
                  <span className="text-[12px] font-medium text-slate-600 truncate">{showCode ? dir.code : dir.name}</span>
                </div>
                {expanded[dir.id] && dir.children && (
                  <div className="ml-5 border-l border-slate-100 mt-0.5 mb-1">
                    {dir.children.map(item => (
                      <div key={item.id} onClick={() => onSelectResource(item)} className="flex items-center gap-2 p-1.5 pl-4 hover:bg-blue-50/50 rounded cursor-pointer group relative">
                        <div className="shrink-0">{getIconForType(item.type)}</div>
                        <span className={`text-[12px] truncate flex-1 transition-colors ${activeTab?.id === item.id ? 'text-blue-600 font-bold' : 'text-slate-500'}`}>
                          {showCode ? item.code : item.name}
                        </span>
                        {!isUserMode && (
                          <button 
                            className="opacity-0 group-hover:opacity-100 p-1 text-slate-300 hover:text-amber-400 transition-all"
                            onClick={(e) => { e.stopPropagation(); /* 触发收藏逻辑 */ }}
                            title="收藏"
                          >
                            <Star size={12} />
                          </button>
                        )}
                      </div>
                    ))}
                  </div>
                )}
              </div>
            ))
          )}
        </div>
      </div>

      <div 
        style={{ 
          height: showContext ? `${contextHeight}px` : '0px',
          opacity: showContext ? 1 : 0
        }} 
        className="border-t border-slate-200 bg-slate-50/80 flex flex-col shrink-0 relative transition-all duration-300 ease-in-out overflow-hidden z-10"
      >
        <div 
          onMouseDown={() => setIsResizingContext(true)}
          className="absolute top-0 left-0 w-full h-1 cursor-row-resize hover:bg-blue-400/30 z-50 active:bg-blue-500"
        />

        <div className="h-9 flex items-center px-3 justify-between border-b border-slate-200 bg-white">
          <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-2">
            {lockedDrawerType === 'console' ? (
              <><Terminal size={12} className="text-blue-600" /> 控制台</>
            ) : (
              <><Compass size={12} className="text-blue-600" /> 元素上下文</>
            )}
          </span>
          <button onClick={onCloseContext} className="p-1 hover:bg-slate-100 rounded text-slate-400 transition-colors">
            <ChevronDown size={14} />
          </button>
        </div>
        <div className="flex-1 overflow-y-auto p-3 no-scrollbar space-y-4">
          {lockedDrawerType === 'console' ? (
            <div className="grid grid-cols-1 gap-1 animate-in fade-in slide-in-from-bottom-2 duration-200">
              {CONSOLE_ITEMS.map(item => (
                <button 
                  key={item.id} 
                  onClick={() => onSelectResource({ id: item.id, name: item.name, type: 'page' })}
                  className="flex items-center gap-3 p-2 rounded-lg text-[12px] text-slate-600 bg-white border border-slate-100 hover:border-blue-300 hover:bg-blue-50/30 hover:text-blue-600 transition-all text-left shadow-sm group"
                >
                  <span className="shrink-0 transition-transform group-hover:scale-110">{item.icon}</span>
                  <span className="truncate flex-1 font-medium">{item.name}</span>
                  <ExternalLink size={10} className="opacity-0 group-hover:opacity-100 text-slate-300" />
                </button>
              ))}
            </div>
          ) : activeTab ? (
            <>
              <div className="bg-white p-2.5 rounded-lg border border-slate-200 shadow-sm space-y-1.5">
                <div className="flex items-center gap-2 text-[12px] font-bold text-slate-800">{activeTab.title}</div>
                <div className="text-[10px] text-slate-400 font-mono">{activeTab.code}</div>
              </div>

              <section className="space-y-1.5">
                <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-1.5"><ShieldCheck size={10} className="text-blue-600" /> 权限信息</h4>
                <div className="bg-white/50 border border-slate-100 rounded-lg p-2 text-[11px] space-y-1">
                  <div className="flex justify-between"><span className="text-slate-500">查看权限:</span><span className="text-slate-700">liuqing, admin</span></div>
                  <div className="flex justify-between"><span className="text-slate-500">管理权限:</span><span className="text-blue-600 font-bold">财务管理员组</span></div>
                </div>
              </section>

              <section className="space-y-1.5">
                <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-1.5">
                  <ArrowUpRight size={10} className="text-blue-600" /> 关联元素
                </h4>
                <div className="space-y-1">
                  {[
                    { id: 'rel_logic_1', name: '财务对账核心逻辑', type: 'logic', code: 'FIN_RECON_LOGIC' },
                    { id: 'rel_model_1', name: 'ERP 基础数据模型', type: 'model', code: 'ERP_BASE_MODEL' }
                  ].map((rel) => (
                    <div 
                      key={rel.id} 
                      onClick={() => onSelectResource(rel)}
                      className="bg-white/50 border border-slate-100 rounded-lg p-2 flex items-center gap-2 hover:bg-white transition-colors cursor-pointer group"
                    >
                      {getIconForType(rel.type as ResourceType)}
                      <div className="flex-1 min-w-0">
                        <div className="text-[11px] font-bold text-slate-700 truncate">{rel.name}</div>
                        <div className="text-[9px] text-slate-400 font-mono truncate">{rel.code}</div>
                      </div>
                      <ExternalLink size={10} className="text-slate-300 group-hover:text-blue-500" />
                    </div>
                  ))}
                </div>
              </section>

              <section className="space-y-1.5">
                <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-1.5">
                  <ArrowDownLeft size={10} className="text-emerald-600" /> 被关联元素
                </h4>
                <div className="space-y-1">
                  {[
                    { id: 'rel_ux_audit', name: '月度财务审计看板', type: 'ux', code: 'MONTHLY_AUDIT_DASH' }
                  ].map((rel) => (
                    <div 
                      key={rel.id} 
                      onClick={() => onSelectResource(rel)}
                      className="bg-white/50 border border-slate-100 rounded-lg p-2 flex items-center gap-2 hover:bg-white transition-colors cursor-pointer group"
                    >
                      {getIconForType(rel.type as ResourceType)}
                      <div className="flex-1 min-w-0">
                        <div className="text-[11px] font-bold text-slate-700 truncate">{rel.name}</div>
                        <div className="text-[9px] text-slate-400 font-mono truncate">{rel.code}</div>
                      </div>
                      <ExternalLink size={10} className="text-slate-300 group-hover:text-emerald-500" />
                    </div>
                  ))}
                </div>
              </section>
            </>
          ) : (
            <div className="h-full flex flex-col items-center justify-center opacity-30 grayscale p-4">
              <Compass size={32} className="mb-2" />
              <p className="text-[10px] font-bold uppercase tracking-widest">未选择元素</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default Explorer;

import React, { useState, useEffect, useCallback, useMemo, useRef } from 'react';
import { 
  Files, 
  Bell, 
  Sparkles, 
  X, 
  ChevronDown, 
  Boxes,
  Layers,
  PanelLeftClose,
  PanelLeft,
  ArrowRight,
  MoreHorizontal
} from 'lucide-react';
import { ViewMode, ResourceItem, ModuleId, Tab } from './types';
import Sidebar from './components/Sidebar';
import Explorer from './components/Explorer';
import MainContent from './components/MainContent';
import AIAssistant from './components/AIAssistant';

const INITIAL_DATA: ResourceItem[] = [
  {
    id: 'f1', name: '0101 每日定时对账核销任务', code: 'TASK_0101', type: 'workflow', description: '自动从ERP拉取流水并进行匹配...', version: 'v2.1', createdBy: 'liuqing', updatedAt: '2025-05-14 10:28:07', unreadCount: 1, tags: ['Finance', 'Batch']
  },
  {
    id: 'f2', name: '财务报表集成接口', code: 'CONN_FIN_REP', type: 'connector', description: '财务报表集成数据流核心连接器', version: 'v1.0.2', createdBy: 'liuqing', updatedAt: '2025-05-14 17:28:09',
  },
  {
    id: 'f3', name: '对账核销模型-核心逻辑', code: 'MODEL_RECON', type: 'model', description: '核心清算与对账业务模型', version: '3.0', createdBy: 'liuqing', updatedAt: '2025-05-23 10:38:41',
  }
];

interface ContextMenu {
  x: number;
  y: number;
  tabId: string;
}

const App: React.FC = () => {
  const [activeModule, setActiveModule] = useState<ModuleId>('resources');
  const [activeDrawerModule, setActiveDrawerModule] = useState<ModuleId | null>('context');
  const [isAIShowing, setIsAIShowing] = useState(false);
  const [interfaceMode, setInterfaceMode] = useState<'dev' | 'user'>('dev');

  const [isNavHidden, setIsNavHidden] = useState(false);
  const [isExplorerHidden, setIsExplorerHidden] = useState(false);
  const [sidebarWidth, setSidebarWidth] = useState(64);

  const [isResizing, setIsResizing] = useState(false);
  const isExpanded = sidebarWidth > 120;

  const [tabs, setTabs] = useState<Tab[]>([
    { id: 'elements-view', title: '元素管理', type: 'folder' }
  ]);
  const [activeTabId, setActiveTabId] = useState<string | null>('elements-view');

  const [contextMenu, setContextMenu] = useState<ContextMenu | null>(null);
  const contextMenuRef = useRef<HTMLDivElement>(null);

  const activeTab = useMemo(() => tabs.find(t => t.id === activeTabId), [tabs, activeTabId]);

  const startResizing = useCallback(() => {
    setIsResizing(true);
  }, []);

  const stopResizing = useCallback(() => {
    setIsResizing(false);
  }, []);

  const resize = useCallback((e: MouseEvent) => {
    if (isResizing) {
      const newWidth = Math.min(Math.max(64, e.clientX), 320);
      setSidebarWidth(newWidth);
    }
  }, [isResizing]);

  useEffect(() => {
    if (isResizing) {
      window.addEventListener('mousemove', resize);
      window.addEventListener('mouseup', stopResizing);
      document.body.style.cursor = 'col-resize';
      document.body.style.userSelect = 'none';
    } else {
      window.removeEventListener('mousemove', resize);
      window.removeEventListener('mouseup', stopResizing);
      document.body.style.cursor = '';
      document.body.style.userSelect = '';
    }
    return () => {
      window.removeEventListener('mousemove', resize);
      window.removeEventListener('mouseup', stopResizing);
    };
  }, [isResizing, resize, stopResizing]);

  useEffect(() => {
    const handleClickOutside = (e: MouseEvent) => {
      if (contextMenuRef.current && !contextMenuRef.current.contains(e.target as Node)) {
        setContextMenu(null);
      }
    };
    if (contextMenu) {
      document.addEventListener('mousedown', handleClickOutside);
    }
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, [contextMenu]);

  const toggleSidebar = () => {
    setSidebarWidth(isExpanded ? 64 : 200);
  };

  const openTab = useCallback((item: ResourceItem | { id: string, name: string, code?: string, type: any, moduleId?: ModuleId, updatedAt?: string }) => {
    setTabs(prevTabs => {
      const existing = prevTabs.find(t => t.id === item.id);
      if (!existing) {
        const moduleId = 'moduleId' in item ? item.moduleId : undefined;
        return [...prevTabs, { 
          id: item.id, 
          title: item.name, 
          code: item.code, 
          type: item.type, 
          moduleId,
          updatedAt: item.updatedAt
        }];
      }
      return prevTabs;
    });
    setActiveTabId(item.id);
  }, []);

  const closeTabAction = useCallback((id: string) => {
    setTabs(prevTabs => {
      const newTabs = prevTabs.filter(t => t.id !== id);
      if (activeTabId === id) {
        if (newTabs.length > 0) {
          const currentIndex = prevTabs.findIndex(t => t.id === id);
          const nextTab = newTabs[Math.min(currentIndex, newTabs.length - 1)];
          setActiveTabId(nextTab.id);
        } else {
          setActiveTabId(null);
        }
      }
      return newTabs;
    });
  }, [activeTabId]);

  const closeRightAction = useCallback((id: string) => {
    setTabs(prevTabs => {
      const index = prevTabs.findIndex(t => t.id === id);
      const newTabs = prevTabs.slice(0, index + 1);
      if (activeTabId && !newTabs.find(t => t.id === activeTabId)) {
        setActiveTabId(id);
      }
      return newTabs;
    });
  }, [activeTabId]);

  const closeOthersAction = useCallback((id: string) => {
    setTabs(prevTabs => {
      const clickedTab = prevTabs.find(t => t.id === id);
      const newTabs = clickedTab ? [clickedTab] : prevTabs;
      setActiveTabId(id);
      return newTabs;
    });
  }, []);

  const handleContextMenu = (e: React.MouseEvent, id: string) => {
    e.preventDefault();
    setContextMenu({
      x: e.clientX,
      y: e.clientY,
      tabId: id
    });
  };

  const handleSidebarModuleChange = (id: string) => {
    if (id === 'elements') {
      openTab({ id: 'elements-view', name: '元素管理', type: 'folder' });
    } else {
      setActiveModule(id as ModuleId);
      if (isExplorerHidden) setIsExplorerHidden(false);
    }
  };

  const explorerWidth = isExplorerHidden ? 0 : 240;
  const navContainerWidth = sidebarWidth + explorerWidth;

  return (
    <div className="flex h-screen w-screen flex-col overflow-hidden bg-white selection:bg-blue-100 antialiased font-sans text-[13px]">
      <header className="h-14 flex items-center border-b border-slate-200 bg-white shrink-0 z-30">
        <div className="flex items-center px-4 h-full shrink-0">
          <button 
            onClick={() => setIsNavHidden(!isNavHidden)}
            className={`p-1.5 rounded-lg transition-all mr-4 ${isNavHidden ? 'text-blue-600 bg-blue-50' : 'text-slate-400 hover:text-blue-600 hover:bg-blue-50'}`}
            title={isNavHidden ? "展开导航" : "收起导航"}
          >
            {isNavHidden ? <PanelLeft size={18} /> : <PanelLeftClose size={18} />}
          </button>

          <div className="flex items-center gap-2.5">
            <div className="w-8 h-8 bg-blue-600 rounded-lg flex items-center justify-center text-white shadow-sm shrink-0">
              <Layers size={18} strokeWidth={2.5} />
            </div>
            <div className="whitespace-nowrap overflow-hidden flex flex-col leading-none">
              <span className="font-black text-slate-800 tracking-tight text-[15px]">DeepFOS</span>
              <span className="text-[9px] text-slate-400 font-bold uppercase tracking-widest mt-0.5">Intelligence Platform</span>
            </div>
          </div>
        </div>

        <div className="w-[1px] h-6 bg-slate-200 mx-4 shrink-0"></div>

        <div className="flex-1 flex h-full overflow-x-auto no-scrollbar items-end gap-0.5">
          {tabs.map((tab) => (
            <div 
              key={tab.id}
              onClick={() => setActiveTabId(tab.id)}
              onContextMenu={(e) => handleContextMenu(e, tab.id)}
              className={`group h-[38px] flex items-center px-4 gap-2 text-[12px] font-medium cursor-pointer transition-all border-t-2 rounded-t-lg shrink-0 select-none ${
                activeTabId === tab.id 
                  ? 'bg-white border-blue-600 text-blue-700 shadow-[0_-2px_6px_rgba(0,0,0,0.02)]' 
                  : 'bg-transparent border-transparent text-slate-400 hover:text-slate-600'
              }`}
            >
              <Files size={12} className={activeTabId === tab.id ? 'text-blue-600' : 'text-slate-400'} />
              <span className="max-w-[140px] truncate">{tab.title}</span>
              <button 
                onClick={(e) => { e.stopPropagation(); closeTabAction(tab.id); }}
                className="p-0.5 rounded-full hover:bg-slate-100 opacity-0 group-hover:opacity-100 transition-opacity ml-1"
              >
                <X size={10} />
              </button>
            </div>
          ))}
        </div>

        <div className="flex items-center gap-4 px-5 border-l border-slate-100 h-full shrink-0">
          <button onClick={() => setIsAIShowing(!isAIShowing)} className={`p-1.5 rounded-lg transition-colors ${isAIShowing ? 'bg-blue-50 text-blue-600' : 'text-slate-400 hover:bg-slate-100'}`}>
            <Sparkles size={18} />
          </button>
          <button className="p-1.5 text-slate-400 hover:bg-slate-100 rounded-lg relative">
            <Bell size={18} />
            <div className="absolute top-1 right-1 w-2 h-2 bg-red-500 rounded-full border border-white"></div>
          </button>
          <div className="flex items-center gap-2 pl-2 border-l border-slate-100 ml-1">
            <div className="w-8 h-8 rounded-full bg-blue-600 flex items-center justify-center text-white text-[12px] font-bold border-2 border-white shadow-sm">LQ</div>
          </div>
        </div>
      </header>

      {/* Tab Context Menu */}
      {contextMenu && (
        <div 
          ref={contextMenuRef}
          className="fixed bg-white border border-slate-200 rounded-lg shadow-xl py-1 z-[100] min-w-[140px] animate-in fade-in zoom-in duration-100"
          style={{ top: contextMenu.y, left: contextMenu.x }}
        >
          <button 
            className="w-full flex items-center gap-3 px-3 py-2 text-[12px] text-slate-600 hover:bg-slate-50 transition-colors"
            onClick={() => { closeTabAction(contextMenu.tabId); setContextMenu(null); }}
          >
            <X size={14} className="text-slate-400" />
            <span>关闭</span>
          </button>
          <button 
            className="w-full flex items-center gap-3 px-3 py-2 text-[12px] text-slate-600 hover:bg-slate-50 transition-colors"
            onClick={() => { closeRightAction(contextMenu.tabId); setContextMenu(null); }}
          >
            <ArrowRight size={14} className="text-slate-400" />
            <span>关闭右侧</span>
          </button>
          <button 
            className="w-full flex items-center gap-3 px-3 py-2 text-[12px] text-slate-600 hover:bg-slate-50 transition-colors"
            onClick={() => { closeOthersAction(contextMenu.tabId); setContextMenu(null); }}
          >
            <MoreHorizontal size={14} className="text-slate-400" />
            <span>关闭其他</span>
          </button>
        </div>
      )}

      <div className="flex flex-1 overflow-hidden relative">
        <div 
          className="flex overflow-hidden transition-all duration-300 ease-in-out border-r border-slate-200 bg-white shrink-0 relative z-20"
          style={{ 
            width: `${navContainerWidth}px`,
            marginLeft: isNavHidden ? `-${navContainerWidth}px` : '0px'
          }}
        >
          <Sidebar 
            activeModule={activeModule} 
            onModuleChange={handleSidebarModuleChange} 
            activeDrawerModule={activeDrawerModule}
            onDrawerChange={(id) => {
              setActiveDrawerModule(activeDrawerModule === id ? null : id);
            }}
            width={sidebarWidth}
            isExpanded={isExpanded}
            onToggleExpand={toggleSidebar}
            onResizeStart={startResizing}
            isResizing={isResizing}
            interfaceMode={interfaceMode}
            onModeToggle={(mode) => {
              setInterfaceMode(mode);
              setActiveModule(mode === 'dev' ? 'resources' : 'finance_center');
              setActiveDrawerModule(null);
              if (isExplorerHidden) setIsExplorerHidden(false);
            }}
          />

          <div className={`flex-1 flex flex-col border-l border-slate-100 bg-white relative overflow-hidden transition-all duration-300 ${isExplorerHidden ? 'opacity-0' : 'opacity-100'}`}>
            <div className="flex-1 flex flex-col min-h-0">
              <Explorer 
                key={`${activeModule}-${interfaceMode}`} 
                activeModule={activeModule} 
                onSelectResource={(item) => openTab(item)}
                isUserMode={interfaceMode === 'user'} 
                activeTab={activeTab}
                showContext={activeDrawerModule !== null}
                activeDrawerType={activeDrawerModule}
                onCloseContext={() => setActiveDrawerModule(null)}
                onToggleCollapse={() => setIsExplorerHidden(true)}
              />
            </div>
          </div>
        </div>

        <main className="flex-1 flex flex-row overflow-hidden relative bg-[#f8fafc] z-10">
          {isExplorerHidden && !isNavHidden && (
            <button 
              onClick={() => setIsExplorerHidden(false)}
              className="absolute left-0 top-1/2 -translate-y-1/2 p-1.5 bg-white border border-slate-200 border-l-0 rounded-r-lg text-slate-400 hover:text-blue-600 shadow-md z-50 animate-in slide-in-from-left duration-200"
              title="展开目录栏"
            >
              <PanelLeft size={16} />
            </button>
          )}
          <div className="flex-1 overflow-hidden">
            <MainContent 
              data={INITIAL_DATA} 
              viewMode={ViewMode.EXPLORER} 
              activeTab={activeTab} 
              onOpenTab={openTab}
            />
          </div>
          {isAIShowing && (
            <div className="w-80 border-l border-slate-200 bg-white shrink-0 animate-in slide-in-from-right duration-300 z-40 shadow-xl">
              <AIAssistant onClose={() => setIsAIShowing(false)} />
            </div>
          )}
        </main>
      </div>
    </div>
  );
};

