          <button 
            onClick={() => onModeToggle('dev')}
            className={`flex items-center gap-2 p-1.5 rounded-lg transition-all w-full ${
              interfaceMode === 'dev' ? 'bg-blue-600 text-white shadow-sm' : 'text-slate-400 hover:bg-slate-50'
