}) => {
  const [selectedModule, setSelectedModule] = useState(isUserMode ? activeModule : 'all');
  const [isModuleMenuOpen, setIsModuleMenuOpen] = useState(false);
  const [isMoreMenuOpen, setIsMoreMenuOpen] = useState(false);
  const [expanded, setExpanded] = useState<Record<string, boolean>>({ 'root_ux': true, 'root_model': true });
  const [groupsExpanded, setGroupsExpanded] = useState<Record<string, boolean>>({
    opened: true,
    fav: true,
    recent: true
  });
  const [showCode, setShowCode] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [contextHeight, setContextHeight] = useState(320);
  const [isResizingContext, setIsResizingContext] = useState(false);

  // 历史记录与常用项状态
  const [historyItems, setHistoryItems] = useState<ResourceItem[]>(INITIAL_HISTORY_ITEMS);
  const [pinnedItems, setPinnedItems] = useState<ResourceItem[]>(INITIAL_FAVORITE_ITEMS);

  const [lockedDrawerType, setLockedDrawerType] = useState<ModuleId | null>(activeDrawerType || null);

  useEffect(() => {
    if (activeDrawerType) setLockedDrawerType(activeDrawerType);
  }, [activeDrawerType]);

  // 当 Tab 被打开时，如果它在最近打开中，记录到历史，但在列表中将其排除（由 useMemo 处理）
  useEffect(() => {
    if (activeTab && !activeTab.id.includes('elements') && !activeTab.id.includes('default')) {
      const exists = historyItems.some(i => i.id === activeTab.id);
      if (!exists) {
        setHistoryItems(prev => [{
          id: activeTab.id,
          name: activeTab.title,
          code: activeTab.code || '',
          type: activeTab.type as any,
          version: '1.0',
          createdBy: 'system',
          updatedAt: new Date().toISOString()
        }, ...prev]);
      }
    }
  }, [activeTab]);

  const toggleExpand = (id: string) => setExpanded(prev => ({ ...prev, [id]: !prev[id] }));
  const toggleGroup = (id: string) => setGroupsExpanded(prev => ({ ...prev, [id]: !prev[id] }));

  // 常用项逻辑
  const handlePin = useCallback((item: ResourceItem) => {
    setPinnedItems(prev => prev.some(i => i.id === item.id) ? prev : [item, ...prev]);
  }, []);

  const handleUnpin = useCallback((itemId: string) => {
    setPinnedItems(prev => prev.filter(i => i.id !== itemId));
  }, []);

  // 已打开的分组数据（排除固有的管理视图）
  const openedList = useMemo(() => {
    return tabs.filter(t => t.id !== 'elements-view' && t.id !== 'default-home');
  }, [tabs]);

  // 最近打开：纯历史，且排除当前已打开的
  const filteredHistory = useMemo(() => {
    const query = searchQuery.toLowerCase();
    const historyPool = historyItems.filter(item => !tabs.some(t => t.id === item.id));
    if (!query) return historyPool;
    return historyPool.filter(item => item.name.toLowerCase().includes(query) || item.code.toLowerCase().includes(query));
  }, [searchQuery, historyItems, tabs]);

  // 常用：过滤搜索，并标记是否已打开
  const filteredPinned = useMemo(() => {
    const query = searchQuery.toLowerCase();
    if (!query) return pinnedItems;
    return pinnedItems.filter(item => item.name.toLowerCase().includes(query) || item.code.toLowerCase().includes(query));
  }, [searchQuery, pinnedItems]);

  const currentTree = useMemo(() => {
    const data = isUserMode ? (MODULE_DATA[activeModule] || []) : (MODULE_DATA[selectedModule] || MODULE_DATA['all'] || []);
    if (!searchQuery) return data;
    const lowerQuery = searchQuery.toLowerCase();
    return data.map(dir => ({
      ...dir,
      children: dir.children?.filter(item => 
        item.name.toLowerCase().includes(lowerQuery) || item.code.toLowerCase().includes(lowerQuery)
      )
    })).filter(dir => (dir.children && dir.children.length > 0) || dir.name.toLowerCase().includes(lowerQuery));
  }, [selectedModule, activeModule, searchQuery, isUserMode]);

  return (
    <div className="flex flex-col h-full bg-white select-none relative border-r border-slate-100">
      <div className="h-14 flex items-center px-4 justify-between border-b border-slate-100 bg-white shrink-0">
        <div className="flex items-center gap-2">
          <span className="font-bold text-slate-800 tracking-tight text-[13px] uppercase">
            {activeModule === 'recent_fav' ? '最近打开' : (isUserMode ? '业务模块' : '资源管理')}
          </span>
        </div>
        <div className="flex items-center gap-1">
          <button onClick={() => setShowCode(!showCode)} className={`p-1.5 rounded transition-all active:scale-90 ${showCode ? 'bg-blue-600 text-white' : 'text-slate-400 hover:bg-slate-50'}`}>
            {showCode ? <Code2 size={14} /> : <Eye size={14} />}
          </button>
          <button onClick={onToggleCollapse} className="p-1.5 text-slate-400 hover:bg-slate-50 rounded">
            <PanelLeftClose size={14} />
          </button>
        </div>
      </div>

      <div className="flex-1 flex flex-col min-h-0 overflow-hidden">
        <div className="p-2 space-y-3">
          <div className="relative">
            <Search className="absolute left-2.5 top-1/2 -translate-y-1/2 text-slate-400" size={13} />
            <input type="text" placeholder="搜索资源..." value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)} className="w-full bg-slate-50 border border-slate-200 rounded py-1.5 pl-8 pr-3 text-[12px] outline-none focus:border-blue-500 focus:bg-white transition-all shadow-sm" />
          </div>
        </div>

        <div className="flex-1 overflow-y-auto px-1 no-scrollbar pb-10">
          {activeModule === 'recent_fav' ? (
            <div className="space-y-5 pt-1">

              {/* 1. 已打开分组 (Sync with Tabs) */}
              <div className="px-1">
                <button onClick={() => toggleGroup('opened')} className="w-full flex items-center justify-between p-1.5 mb-1 text-slate-400 bg-slate-50/50 rounded hover:bg-slate-100/50 transition-colors">
                  <div className="flex items-center gap-2">
                    <History size={14} className="text-blue-600" />
                    <span className="text-[11px] font-black uppercase tracking-widest">已打开</span>
                    {openedList.length > 0 && <span className="bg-blue-100 text-blue-600 px-1 rounded text-[9px] font-bold">{openedList.length}</span>}
                  </div>
                  {groupsExpanded.opened ? <ChevronDown size={12} /> : <ChevronRight size={12} />}
                </button>
                {groupsExpanded.opened && (
                  <div className="space-y-0.5 animate-in fade-in slide-in-from-top-1 duration-200">
                    {openedList.length > 0 ? openedList.map(item => (
                      <div key={item.id} onClick={() => onSelectResource({ id: item.id, name: item.title, type: item.type })} className={`flex items-center gap-2 p-1.5 rounded cursor-pointer group transition-all ${activeTab?.id === item.id ? 'bg-blue-600/5 shadow-inner' : 'hover:bg-blue-50/50'}`}>
                        {getIconForType(item.type as ResourceType)}
                        <span className={`text-[12px] truncate flex-1 transition-all ${activeTab?.id === item.id ? 'text-blue-600 font-bold' : 'text-slate-500'}`}>
                          {item.title}
                        </span>
                        <button onClick={(e) => { e.stopPropagation(); onCloseTab(item.id); }} className="opacity-0 group-hover:opacity-100 p-1 text-slate-300 hover:text-rose-500 rounded hover:bg-rose-50 transition-all">
                          <X size={12} />
                        </button>
                      </div>
                    )) : <div className="p-3 text-[11px] text-slate-400 text-center italic">暂无打开的标签页</div>}
                  </div>
                )}
              </div>

              {/* 2. 常用分组 (With Open State Indicator) */}
              <div className="px-1">
                <button onClick={() => toggleGroup('fav')} className="w-full flex items-center justify-between p-1.5 mb-1 text-slate-400 bg-slate-50/50 rounded hover:bg-slate-100/50 transition-colors">
                  <div className="flex items-center gap-2">
                    <Pin size={14} className="text-blue-600" />
                    <span className="text-[11px] font-black uppercase tracking-widest">常用</span>
                  </div>
                  {groupsExpanded.fav ? <ChevronDown size={12} /> : <ChevronRight size={12} />}
                </button>
                {groupsExpanded.fav && (
                  <div className="space-y-0.5 animate-in fade-in slide-in-from-top-1 duration-200">
                    {filteredPinned.length > 0 ? filteredPinned.map(item => {
                      const isOpen = tabs.some(t => t.id === item.id);
                      return (
                        <div key={item.id} onClick={() => onSelectResource(item)} className="flex items-center gap-2 p-1.5 rounded cursor-pointer hover:bg-blue-50/50 transition-colors group">
                          {getIconForType(item.type)}
                          <span className={`text-[12px] truncate flex-1 transition-all ${isOpen ? 'text-blue-600 font-bold' : 'text-slate-500'}`}>
                            {showCode ? item.code : item.name}
                          </span>
                          {isOpen && <div className="w-1.5 h-1.5 bg-blue-500 rounded-full animate-pulse shadow-sm shadow-blue-400"></div>}
                          <button className="opacity-0 group-hover:opacity-100 p-1 text-slate-300 hover:text-blue-600 hover:bg-blue-50 rounded" onClick={(e) => { e.stopPropagation(); handleUnpin(item.id); }}>
                            <PinOff size={12} />
                          </button>
                        </div>
                      );
                    }) : <div className="p-3 text-[11px] text-slate-400 text-center italic">无常用资源</div>}
                  </div>
                )}
              </div>

              {/* 3. 最近打开 (Pure History) */}
              <div className="px-1">
                <button onClick={() => toggleGroup('recent')} className="w-full flex items-center justify-between p-1.5 mb-1 text-slate-400 bg-slate-50/50 rounded hover:bg-slate-100/50 transition-colors">
                  <div className="flex items-center gap-2">
                    <Clock size={14} />
                    <span className="text-[11px] font-black uppercase tracking-widest">最近打开 (历史)</span>
                  </div>
                  {groupsExpanded.recent ? <ChevronDown size={12} /> : <ChevronRight size={12} />}
                </button>
                {groupsExpanded.recent && (
                  <div className="space-y-0.5 animate-in fade-in slide-in-from-top-1 duration-200">
                    {filteredHistory.length > 0 ? filteredHistory.map(item => {
                      const isPinned = pinnedItems.some(p => p.id === item.id);
                      return (
                        <div key={item.id} onClick={() => onSelectResource(item)} className="flex items-center gap-2 p-1.5 rounded cursor-pointer hover:bg-blue-50/50 transition-colors group">
                          {getIconForType(item.type)}
                          <span className={`text-[12px] truncate flex-1 text-slate-500`}>
                            {showCode ? item.code : item.name}
                          </span>
                          <button 
                            className={`p-1 rounded transition-all ${isPinned ? 'text-blue-600 opacity-50' : 'opacity-0 group-hover:opacity-100 text-slate-400 hover:text-blue-600 hover:bg-blue-50'}`}
                            onClick={(e) => { e.stopPropagation(); if (!isPinned) handlePin(item); }}
                          >
                            <Pin size={12} fill={isPinned ? "currentColor" : "none"} />
                          </button>
                        </div>
                      );
                    }) : <div className="p-3 text-[11px] text-slate-400 text-center italic">暂无历史记录</div>}
                  </div>
                )}
              </div>

            </div>
          ) : (
            currentTree.map(dir => (
              <div key={dir.id} className="mb-0.5">
                <div onClick={() => toggleExpand(dir.id)} className="flex items-center gap-2 p-1.5 hover:bg-slate-100/60 rounded cursor-pointer group">
                  <div className="w-4 h-4 flex items-center justify-center shrink-0">
                    {expanded[dir.id] ? <ChevronDown size={12} className="text-slate-400" /> : <ChevronRight size={12} className="text-slate-400" />}
                  </div>
                  {getIconForType('folder')}
                  <span className="text-[12px] font-medium text-slate-600 truncate">{showCode ? dir.code : dir.name}</span>
                </div>
                {expanded[dir.id] && dir.children && (
                  <div className="ml-5 border-l border-slate-100 mt-0.5 mb-1">
                    {dir.children.map(item => (
                      <div key={item.id} onClick={() => onSelectResource(item)} className="flex items-center gap-2 p-1.5 pl-4 hover:bg-blue-50/50 rounded cursor-pointer group relative">
                        {getIconForType(item.type)}
                        <span className={`text-[12px] truncate flex-1 transition-colors ${activeTab?.id === item.id ? 'text-blue-600 font-bold' : 'text-slate-500'}`}>
                          {showCode ? item.code : item.name}
                        </span>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            ))
          )}
        </div>
      </div>

      <div style={{ height: showContext ? `${contextHeight}px` : '0px', opacity: showContext ? 1 : 0 }} className="border-t border-slate-200 bg-slate-50/80 flex flex-col shrink-0 relative transition-all duration-300 ease-in-out overflow-hidden z-10">
        <div onMouseDown={() => setIsResizingContext(true)} className="absolute top-0 left-0 w-full h-1 cursor-row-resize hover:bg-blue-400/30 z-50 active:bg-blue-500" />
        <div className="h-9 flex items-center px-3 justify-between border-b border-slate-200 bg-white">
          <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-2">
            {lockedDrawerType === 'console' ? <><Terminal size={12} className="text-blue-600" /> 控制台</> : <><Info size={12} className="text-blue-600" /> 元素信息</>}
          </span>
          <button onClick={onCloseContext} className="p-1 hover:bg-slate-100 rounded text-slate-400"><ChevronDown size={14} /></button>
        </div>
        <div className="flex-1 overflow-y-auto p-3 no-scrollbar space-y-4">
          {lockedDrawerType === 'console' ? (
            <div className="grid grid-cols-1 gap-1 animate-in fade-in slide-in-from-bottom-2 duration-200">
              {CONSOLE_ITEMS.map(item => (
                <button key={item.id} onClick={() => onSelectResource({ id: item.id, name: item.name, type: 'page' })} className="flex items-center gap-3 p-2 rounded-lg text-[12px] text-slate-600 bg-white border border-slate-100 hover:border-blue-300 hover:bg-blue-50/30 hover:text-blue-600 transition-all text-left shadow-sm group">
                  <span className="shrink-0 transition-transform group-hover:scale-110">{item.icon}</span>
                  <span className="truncate flex-1 font-medium">{item.name}</span>
                </button>
              ))}
            </div>
          ) : activeTab ? (
            <>
              <div className="bg-white p-2.5 rounded-lg border border-slate-200 shadow-sm space-y-1.5">
                <div className="flex items-center gap-2 text-[12px] font-bold text-slate-800">{activeTab.title}</div>
                <div className="text-[10px] text-slate-400 font-mono">{activeTab.code}</div>
              </div>
              <section className="space-y-1.5">
                <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-1.5"><ShieldCheck size={10} className="text-blue-600" /> 权限信息</h4>
                <div className="bg-white/50 border border-slate-100 rounded-lg p-2 text-[11px] space-y-1">
                  <div className="flex justify-between"><span className="text-slate-500">管理权限:</span><span className="text-blue-600 font-bold">财务管理员组</span></div>
                </div>
              </section>
            </>
          ) : (
            <div className="h-full flex flex-col items-center justify-center opacity-30 grayscale p-4">
              <Info size={32} className="mb-2" />
              <p className="text-[10px] font-bold uppercase tracking-widest">未选择元素</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default Explorer;

import React, { useState, useMemo, useCallback, useEffect, useRef } from 'react';
import { 
  ChevronDown, 
  ChevronRight, 
  Search,
  FolderOpen,
  FileText,
  Database,
  Workflow,
  Cpu,
  Code2,
  Eye,
  Plus,
  ArrowUpRight,
  ArrowDownLeft,
  X,
  Compass,
  ShieldCheck,
  ExternalLink,
  History,
  Star,
  Layout,
  Zap,
  Grid3X3,
  MoreVertical,
  Locate,
  Clock,
  Activity,
  ListTodo,
  Monitor,
  PanelLeftClose,
  FileJson,
  Lock,
  PieChart,
  Terminal,
  Info,
  Pin,
  PinOff
} from 'lucide-react';
import { ModuleId, ResourceItem, Tab, ResourceType } from '../types';

interface ExplorerProps {
