  onSelectResource: (item: any) => void;
  isUserMode?: boolean;
  activeTab?: Tab;
  tabs: Tab[]; // 新增：当前所有打开的标签页
  onCloseTab: (id: string) => void; // 新增：关闭标签页的回调
  showContext?: boolean;
  activeDrawerType?: ModuleId | null;
  onCloseContext?: () => void;
  onToggleCollapse?: () => void;
}

