  switch (type) {
    case 'folder': return <FolderOpen size={14} className="text-amber-500 fill-amber-500/10" />;
    case 'model': return <Database size={14} className="text-purple-500" />;
    case 'logic': return <Workflow size={14} className="text-sky-500" />;
    case 'workflow': return <Cpu size={14} className="text-indigo-500" />;
    case 'spreadsheet': return <Grid3X3 size={14} className="text-emerald-500" />;
    case 'ux': return <Layout size={14} className="text-blue-500" />;
    case 'accounting': return <History size={14} className="text-rose-500" />;
    case 'script': return <Terminal size={14} className="text-slate-500" />;
    default: return <FileText size={14} className="text-slate-400" />;
  }
};

const Explorer: React.FC<ExplorerProps> = ({ 
  activeModule,
  onSelectResource, 
  isUserMode, 
  activeTab,
  tabs,
  onCloseTab,
  showContext = true,
  activeDrawerType,
  onCloseContext,
  onToggleCollapse
}) => {
  const [selectedModule, setSelectedModule] = useState(isUserMode ? activeModule : 'all');
  const [groupsExpanded, setGroupsExpanded] = useState<Record<string, boolean>>({
    recent: true,
    fav: true
  });
  const [showCode, setShowCode] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [contextHeight, setContextHeight] = useState(320);
  const [isResizingContext, setIsResizingContext] = useState(false);

  // 1. 历史记录状态管理
  const [historyItems, setHistoryItems] = useState<ResourceItem[]>(INITIAL_HISTORY_ITEMS);
  const [pinnedItems, setPinnedItems] = useState<ResourceItem[]>(INITIAL_FAVORITE_ITEMS);

  // 用于追踪 Tabs 的前一个状态以检测哪些 tab 被关掉了
  const prevTabsRef = useRef<Tab[]>(tabs);

  // 2. 检测 Tab 关闭与开启的逻辑
  useEffect(() => {
    const prevTabs = prevTabsRef.current;

    // A. 检测哪些 Tab 被关闭了 -> 移动到历史记录顶端
    const closedTabs = prevTabs.filter(prev => !tabs.some(curr => curr.id === prev.id));
    if (closedTabs.length > 0) {
      setHistoryItems(prev => {
        let newHistory = [...prev];
        closedTabs.forEach(closed => {
          // 排除固有的管理页
          if (closed.id === 'elements-view' || closed.id === 'default-home') return;

          // 先移除已有的(如有)，再放到最上面
          newHistory = newHistory.filter(h => h.id !== closed.id);
          const historyEntry: ResourceItem = {
            id: closed.id,
            name: closed.title,
            code: closed.code || '',
            type: closed.type as any,
            version: '1.0',
            createdBy: 'system',
            updatedAt: new Date().toISOString()
          };
          newHistory = [historyEntry, ...newHistory];
        });
        // 最多存 10 条
        return newHistory.slice(0, 10);
      });
    }

    // B. 检测哪些 Tab 被新开启了 -> 从历史记录中移除
    const openedTabs = tabs.filter(curr => !prevTabs.some(prev => prev.id === curr.id));
    if (openedTabs.length > 0) {
      setHistoryItems(prev => prev.filter(h => !openedTabs.some(o => o.id === h.id)));
    }

    prevTabsRef.current = tabs;
  }, [tabs]);

  const toggleExpand = (id: string) => setExpanded(prev => ({ ...prev, [id]: !prev[id] }));
  const toggleGroup = (id: string) => setGroupsExpanded(prev => ({ ...prev, [id]: !prev[id] }));
  const [expanded, setExpanded] = useState<Record<string, boolean>>({ 'root_ux': true, 'root_model': true });

  const handlePin = useCallback((item: ResourceItem) => {
    setPinnedItems(prev => prev.some(i => i.id === item.id) ? prev : [item, ...prev]);
  }, []);

  const handleUnpin = useCallback((itemId: string) => {
    setPinnedItems(prev => prev.filter(i => i.id !== itemId));
  }, []);

  // 已打开的资源 Tabs
  const activeOpenedTabs = useMemo(() => {
    return tabs.filter(t => t.id !== 'elements-view' && t.id !== 'default-home');
  }, [tabs]);

  // 搜索过滤后的历史记录
  const filteredHistory = useMemo(() => {
    const q = searchQuery.toLowerCase();
    if (!q) return historyItems;
    return historyItems.filter(h => h.name.toLowerCase().includes(q) || h.code.toLowerCase().includes(q));
  }, [searchQuery, historyItems]);

  // 搜索过滤后的常用项
  const filteredPinned = useMemo(() => {
    const q = searchQuery.toLowerCase();
    if (!q) return pinnedItems;
    return pinnedItems.filter(p => p.name.toLowerCase().includes(q) || p.code.toLowerCase().includes(q));
  }, [searchQuery, pinnedItems]);

  const currentTree = useMemo(() => {
    const data = isUserMode ? (MODULE_DATA[activeModule] || []) : (MODULE_DATA[selectedModule] || MODULE_DATA['all'] || []);
    if (!searchQuery) return data;
    const lowerQuery = searchQuery.toLowerCase();
    return data.map(dir => ({
      ...dir,
      children: dir.children?.filter(item => 
        item.name.toLowerCase().includes(lowerQuery) || item.code.toLowerCase().includes(lowerQuery)
      )
    })).filter(dir => (dir.children && dir.children.length > 0) || dir.name.toLowerCase().includes(lowerQuery));
  }, [selectedModule, activeModule, searchQuery, isUserMode]);

  return (
    <div className="flex flex-col h-full bg-white select-none relative border-r border-slate-100">
      <div className="h-14 flex items-center px-4 justify-between border-b border-slate-100 bg-white shrink-0">
        <div className="flex items-center gap-2">
          <span className="font-bold text-slate-800 tracking-tight text-[13px] uppercase">
            {activeModule === 'recent_fav' ? '最近打开' : (isUserMode ? '业务模块' : '资源管理')}
          </span>
        </div>
        <div className="flex items-center gap-1">
          <button onClick={() => setShowCode(!showCode)} className={`p-1.5 rounded transition-all active:scale-90 ${showCode ? 'bg-blue-600 text-white shadow-sm' : 'text-slate-400 hover:bg-slate-50'}`}>
            {showCode ? <Code2 size={14} /> : <Eye size={14} />}
          </button>
          <button onClick={onToggleCollapse} className="p-1.5 text-slate-400 hover:bg-slate-50 rounded transition-colors">
            <PanelLeftClose size={14} />
          </button>
        </div>
      </div>

      <div className="flex-1 flex flex-col min-h-0 overflow-hidden">
        <div className="p-2 space-y-3">
          <div className="relative">
            <Search className="absolute left-2.5 top-1/2 -translate-y-1/2 text-slate-400" size={13} />
            <input type="text" placeholder="搜索资源..." value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)} className="w-full bg-slate-50 border border-slate-200 rounded py-1.5 pl-8 pr-3 text-[12px] outline-none focus:border-blue-500 focus:bg-white transition-all shadow-sm" />
          </div>
        </div>

        <div className="flex-1 overflow-y-auto px-1 no-scrollbar pb-10">
          {activeModule === 'recent_fav' ? (
            <div className="space-y-4 pt-1">

              {/* 1. 常用 (Pinned Items) - 保持在最上方 */}
              <div className="px-1">
                <button onClick={() => toggleGroup('fav')} className="w-full flex items-center justify-between p-1.5 mb-1 text-slate-400 bg-slate-50/50 rounded hover:bg-slate-100/50 transition-colors">
                  <div className="flex items-center gap-2">
                    <Star size={14} className="text-amber-500 fill-amber-500/20" />
                    <span className="text-[11px] font-black uppercase tracking-widest">常用</span>
                  </div>
                  {groupsExpanded.fav ? <ChevronDown size={12} /> : <ChevronRight size={12} />}
                </button>
                {groupsExpanded.fav && (
                  <div className="space-y-0.5 animate-in fade-in slide-in-from-top-1 duration-200">
                    {filteredPinned.length > 0 ? filteredPinned.map(item => {
                      const isOpen = tabs.some(t => t.id === item.id);
                      const isActive = activeTab?.id === item.id;
                      return (
                        <div key={item.id} onClick={() => onSelectResource(item)} className={`flex items-center gap-2 p-1.5 rounded cursor-pointer group transition-all ${isActive ? 'bg-blue-600/5 shadow-inner' : 'hover:bg-blue-50/50'}`}>
                          {getIconForType(item.type)}
                          <span className={`text-[12px] truncate flex-1 transition-all ${isActive ? 'text-blue-600 font-bold' : (isOpen ? 'text-slate-700' : 'text-slate-500')}`}>
                            {showCode ? item.code : item.name}
                          </span>
                          {isOpen && <div className="w-1.5 h-1.5 bg-blue-500 rounded-full animate-pulse"></div>}
                          <button className="opacity-0 group-hover:opacity-100 p-1 text-slate-300 hover:text-blue-600 hover:bg-blue-50 rounded" onClick={(e) => { e.stopPropagation(); handleUnpin(item.id); }}>
                            <PinOff size={12} />
                          </button>
                        </div>
                      );
                    }) : <div className="p-3 text-[11px] text-slate-400 text-center italic">暂无常用项</div>}
                  </div>
                )}
              </div>

              {/* 2. 最近 (Merged: Opened + History) */}
              <div className="px-1">
                <button onClick={() => toggleGroup('recent')} className="w-full flex items-center justify-between p-1.5 mb-1 text-slate-400 bg-slate-50/50 rounded hover:bg-slate-100/50 transition-colors">
                  <div className="flex items-center gap-2">
                    <History size={14} className="text-blue-600" />
                    <span className="text-[11px] font-black uppercase tracking-widest">最近</span>
                    {(activeOpenedTabs.length + historyItems.length) > 0 && (
                      <span className="bg-slate-200 text-slate-600 px-1 rounded text-[9px] font-bold">
                        {activeOpenedTabs.length + historyItems.length}
                      </span>
                    )}
                  </div>
                  {groupsExpanded.recent ? <ChevronDown size={12} /> : <ChevronRight size={12} />}
                </button>

                {groupsExpanded.recent && (
                  <div className="space-y-0.5 animate-in fade-in slide-in-from-top-1 duration-200">

                    {/* A. 已打开的部分 */}
                    {activeOpenedTabs.map(item => (
                      <div key={item.id} onClick={() => onSelectResource({ id: item.id, name: item.title, type: item.type, code: item.code })} className={`flex items-center gap-2 p-1.5 rounded cursor-pointer group transition-all ${activeTab?.id === item.id ? 'bg-blue-600/5 shadow-inner' : 'hover:bg-blue-50/50'}`}>
                        {getIconForType(item.type as ResourceType)}
                        <span className={`text-[12px] truncate flex-1 transition-all ${activeTab?.id === item.id ? 'text-blue-600 font-bold' : 'text-slate-700 font-medium'}`}>
                          {showCode ? (item.code || item.title) : item.title}
                        </span>
                        <button onClick={(e) => { e.stopPropagation(); onCloseTab(item.id); }} className="opacity-0 group-hover:opacity-100 p-1 text-slate-300 hover:text-rose-500 rounded hover:bg-rose-50 transition-all">
                          <X size={12} />
                        </button>
                      </div>
                    ))}

                    {/* 分割线 - 只有当两部分都有内容时更有意义，但始终显示以区分状态 */}
                    {(activeOpenedTabs.length > 0 && filteredHistory.length > 0) && (
                      <div className="flex items-center gap-2 py-1 px-2">
                        <div className="flex-1 h-[1px] bg-slate-100"></div>
                        <div className="text-[8px] font-black text-slate-300 uppercase tracking-tighter">历史记录</div>
                        <div className="flex-1 h-[1px] bg-slate-100"></div>
                      </div>
                    )}

                    {/* B. 历史记录部分 (灰色) */}
                    {filteredHistory.map(item => {
                      const isPinned = pinnedItems.some(p => p.id === item.id);
                      return (
                        <div key={item.id} onClick={() => onSelectResource(item)} className="flex items-center gap-2 p-1.5 rounded cursor-pointer group hover:bg-slate-50 transition-colors">
                          <div className="opacity-40 grayscale">{getIconForType(item.type)}</div>
                          <span className={`text-[12px] truncate flex-1 text-slate-400 transition-colors group-hover:text-slate-500 italic`}>
                            {showCode ? item.code : item.name}
                          </span>
                          <button 
                            className={`p-1 rounded transition-all ${isPinned ? 'text-blue-600 opacity-40' : 'opacity-0 group-hover:opacity-100 text-slate-300 hover:text-blue-600 hover:bg-blue-50'}`}
                            onClick={(e) => { e.stopPropagation(); if (!isPinned) handlePin(item); }}
                          >
                            <Pin size={12} fill={isPinned ? "currentColor" : "none"} />
                          </button>
                        </div>
                      );
                    })}

                    {activeOpenedTabs.length === 0 && filteredHistory.length === 0 && (
                      <div className="p-4 text-[11px] text-slate-300 text-center">暂无最近活动</div>
                    )}
                  </div>
                )}
              </div>

            </div>
          ) : (
            currentTree.map(dir => (
              <div key={dir.id} className="mb-0.5">
                <div onClick={() => toggleExpand(dir.id)} className="flex items-center gap-2 p-1.5 hover:bg-slate-100/60 rounded cursor-pointer group">
                  <div className="w-4 h-4 flex items-center justify-center shrink-0">
                    {expanded[dir.id] ? <ChevronDown size={12} className="text-slate-400" /> : <ChevronRight size={12} className="text-slate-400" />}
                  </div>
                  {getIconForType('folder')}
                  <span className="text-[12px] font-medium text-slate-600 truncate">{showCode ? dir.code : dir.name}</span>
                </div>
                {expanded[dir.id] && dir.children && (
                  <div className="ml-5 border-l border-slate-100 mt-0.5 mb-1">
                    {dir.children.map(item => (
                      <div key={item.id} onClick={() => onSelectResource(item)} className="flex items-center gap-2 p-1.5 pl-4 hover:bg-blue-50/50 rounded cursor-pointer group relative">
                        {getIconForType(item.type)}
                        <span className={`text-[12px] truncate flex-1 transition-colors ${activeTab?.id === item.id ? 'text-blue-600 font-bold' : 'text-slate-500'}`}>
                          {showCode ? item.code : item.name}
                        </span>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            ))
          )}
        </div>
      </div>

      <div style={{ height: showContext ? `${contextHeight}px` : '0px', opacity: showContext ? 1 : 0 }} className="border-t border-slate-200 bg-slate-50/80 flex flex-col shrink-0 relative transition-all duration-300 ease-in-out overflow-hidden z-10">
        <div onMouseDown={() => setIsResizingContext(true)} className="absolute top-0 left-0 w-full h-1 cursor-row-resize hover:bg-blue-400/30 z-50 active:bg-blue-500" />
        <div className="h-9 flex items-center px-3 justify-between border-b border-slate-200 bg-white">
          <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-2">
            {lockedDrawerType === 'console' ? <><Terminal size={12} className="text-blue-600" /> 控制台</> : <><Info size={12} className="text-blue-600" /> 元素信息</>}
          </span>
          <button onClick={onCloseContext} className="p-1 hover:bg-slate-100 rounded text-slate-400"><ChevronDown size={14} /></button>
        </div>
        <div className="flex-1 overflow-y-auto p-3 no-scrollbar space-y-4">
          {lockedDrawerType === 'console' ? (
            <div className="grid grid-cols-1 gap-1">
              {CONSOLE_ITEMS.map(item => (
                <button key={item.id} onClick={() => onSelectResource({ id: item.id, name: item.name, type: 'page' })} className="flex items-center gap-3 p-2 rounded-lg text-[12px] text-slate-600 bg-white border border-slate-100 hover:border-blue-300 hover:bg-blue-50/30 hover:text-blue-600 transition-all text-left shadow-sm group">
                  <span className="shrink-0 transition-transform group-hover:scale-110">{item.icon}</span>
                  <span className="truncate flex-1 font-medium">{item.name}</span>
                </button>
              ))}
            </div>
          ) : activeTab ? (
            <>
              <div className="bg-white p-2.5 rounded-lg border border-slate-200 shadow-sm space-y-1.5">
                <div className="flex items-center gap-2 text-[12px] font-bold text-slate-800">{activeTab.title}</div>
                <div className="text-[10px] text-slate-400 font-mono">{activeTab.code}</div>
              </div>
              <section className="space-y-1.5">
                <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-1.5"><ShieldCheck size={10} className="text-blue-600" /> 权限信息</h4>
                <div className="bg-white/50 border border-slate-100 rounded-lg p-2 text-[11px] space-y-1">
                  <div className="flex justify-between"><span className="text-slate-500">管理权限:</span><span className="text-blue-600 font-bold">财务管理员组</span></div>
                </div>
              </section>
            </>
          ) : (
            <div className="h-full flex flex-col items-center justify-center opacity-30 grayscale p-4">
              <Info size={32} className="mb-2" />
              <p className="text-[10px] font-bold uppercase tracking-widest">未选择元素</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default Explorer;

import React, { useState, useMemo, useCallback, useEffect, useRef } from 'react';
import { 
  ChevronDown, 
  ChevronRight, 
  Search,
  FolderOpen,
  FileText,
  Database,
  Workflow,
  Cpu,
  Code2,
  Eye,
  X,
  Star,
  Layout,
  Clock,
  Activity,
  ListTodo,
  PanelLeftClose,
  Terminal,
  Info,
  Pin,
  PinOff,
  History as HistoryIcon
} from 'lucide-react';
import { ModuleId, ResourceItem, Tab, ResourceType } from '../types';

interface ExplorerProps {
  activeModule: ModuleId;
  onSelectResource: (item: any) => void;
  isUserMode?: boolean;
  activeTab?: Tab;
  tabs: Tab[];
  onCloseTab: (id: string) => void;
  showContext?: boolean;
  activeDrawerType?: ModuleId | null;
  onCloseContext?: () => void;
  onToggleCollapse?: () => void;
}

const MODULE_DATA: Record<string, ResourceItem[]> = {
  'module-ux': [
    { id: 'dir_ux_1', name: '电子表格', code: 'DIR_SPREADSHEET', type: 'folder', version: '', createdBy: '', updatedAt: '', children: [
      { id: 'res_ux_1', name: '年度预算录入表', code: 'BUDGET_SHEET', type: 'spreadsheet', version: '1.0', createdBy: 'liuqing', updatedAt: '2025-05-10' },
      { id: 'res_ux_2', name: '费用报销明细', code: 'EXPENSE_DETAIL', type: 'spreadsheet', version: '2.1', createdBy: 'admin', updatedAt: '2025-05-11' },
    ]},
    { id: 'dir_ux_2', name: 'UX 页面', code: 'DIR_UX_PAGE', type: 'folder', version: '', createdBy: '', updatedAt: '', children: [
      { id: 'res_ux_3', name: '财务看板-主视图', code: 'FIN_DASHBOARD', type: 'ux', version: '1.0', createdBy: 'liuqing', updatedAt: '2025-05-12' },
    ]}
  ],
  'finance_center': [
    { id: 'root_statement', name: '财务报表', code: 'ROOT_FIN_STMT', type: 'folder', version: '', createdBy: '', updatedAt: '', children: [
      { id: 'res_stmt_1', name: '合并资产负债表', code: 'CONSOL_BS', type: 'spreadsheet', version: '1.0', createdBy: 'liuqing', updatedAt: '2025-05-15' },
    ]},
  ],
  'all': [
    { id: 'root_ux', name: '01 页面展现', code: 'ROOT_UX', type: 'folder', version: '', createdBy: '', updatedAt: '', children: [
      { id: 'res_ux_1', name: '年度预算录入表', code: 'BUDGET_SHEET', type: 'spreadsheet', version: '1.0', createdBy: 'liuqing', updatedAt: '2025-05-10' },
    ]},
    { id: 'root_model', name: '02 数据模型', code: 'ROOT_MODEL', type: 'folder', version: '', createdBy: '', updatedAt: '', children: [
      { id: 'res_m_1', name: '对账核销核心模型', code: 'MODEL_RECON_CORE', type: 'model', version: '3.0', createdBy: 'liuqing', updatedAt: '2025-05-14' },
    ]},
  ]
};

const INITIAL_FAVORITE_ITEMS: ResourceItem[] = [
  { id: 'res_ux_1', name: '年度预算录入表', code: 'BUDGET_SHEET', type: 'spreadsheet', version: '1.0', createdBy: 'liuqing', updatedAt: '2025-05-10' },
];

const INITIAL_HISTORY_ITEMS: ResourceItem[] = [
  { id: 'res_ux_comp_1', name: '利润分配逻辑表', code: 'PROFIT_DIST', type: 'spreadsheet', version: '1.0', createdBy: 'liuqing', updatedAt: '2025-05-12' },
  { id: 'res_l_1', name: '月度折旧计提逻辑', code: 'DEPRECIATION_LOGIC', type: 'script', version: '1.0', createdBy: 'liuqing', updatedAt: '2025-05-24' },
];

const CONSOLE_ITEMS = [
  { id: 'c1', name: '执行记录', icon: <Activity size={14} /> },
  { id: 'c2', name: '系统日志', icon: <Terminal size={14} /> },
];

const getIconForType = (type: ResourceType) => {
  switch (type) {
    case 'folder': return <FolderOpen size={14} className="text-amber-500 fill-amber-500/10" />;
    case 'model': return <Database size={14} className="text-purple-500" />;
    case 'logic': return <Workflow size={14} className="text-sky-500" />;
    case 'workflow': return <Cpu size={14} className="text-indigo-500" />;
    case 'spreadsheet': return <Grid3X3 size={14} className="text-emerald-500" />;
    case 'ux': return <Layout size={14} className="text-blue-500" />;
    case 'accounting': return <HistoryIcon size={14} className="text-rose-500" />;
    case 'script': return <Terminal size={14} className="text-slate-500" />;
    default: return <FileText size={14} className="text-slate-400" />;
  }
};

const Explorer: React.FC<ExplorerProps> = ({ 
  activeModule,
  onSelectResource, 
  isUserMode, 
  activeTab,
  tabs,
  onCloseTab,
  showContext = true,
  activeDrawerType,
  onCloseContext,
  onToggleCollapse
}) => {
  const [selectedModule, setSelectedModule] = useState(isUserMode ? activeModule : 'all');
  const [expanded, setExpanded] = useState<Record<string, boolean>>({ 'root_ux': true, 'root_model': true });
  const [groupsExpanded, setGroupsExpanded] = useState<Record<string, boolean>>({
    recent: true,
    fav: true
  });
  const [showCode, setShowCode] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [contextHeight, setContextHeight] = useState(320);
  const [isResizingContext, setIsResizingContext] = useState(false);

  // 历史记录与常用项状态
  const [historyItems, setHistoryItems] = useState<ResourceItem[]>(INITIAL_HISTORY_ITEMS);
  const [pinnedItems, setPinnedItems] = useState<ResourceItem[]>(INITIAL_FAVORITE_ITEMS);

  // 追踪 Tabs 变化以管理历史
  const prevTabsRef = useRef<Tab[]>(tabs);

  useEffect(() => {
    const prevTabs = prevTabsRef.current;

    // 1. 查找被关闭的 Tab
    const closedTabs = prevTabs.filter(prev => !tabs.some(curr => curr.id === prev.id));
    if (closedTabs.length > 0) {
      setHistoryItems(prev => {
        let newHistory = [...prev];
        closedTabs.forEach(closed => {
          // 排除非资源的固有管理视图
          if (closed.id === 'elements-view' || closed.id === 'default-home') return;

          // 移除历史中重复的项，并将最新关闭的移到最上方
          newHistory = newHistory.filter(h => h.id !== closed.id);
          const historyEntry: ResourceItem = {
            id: closed.id,
            name: closed.title,
            code: closed.code || '',
            type: closed.type as any,
            version: '1.0',
            createdBy: 'system',
            updatedAt: new Date().toISOString()
          };
          newHistory = [historyEntry, ...newHistory];
        });
        // 限制最多 10 条历史
        return newHistory.slice(0, 10);
      });
    }

    // 2. 查找新开启的 Tab (如果该项在历史中，则移除它)
    const openedTabs = tabs.filter(curr => !prevTabs.some(prev => prev.id === curr.id));
    if (openedTabs.length > 0) {
      setHistoryItems(prev => prev.filter(h => !openedTabs.some(o => o.id === h.id)));
    }

    prevTabsRef.current = tabs;
  }, [tabs]);

  const toggleExpand = (id: string) => setExpanded(prev => ({ ...prev, [id]: !prev[id] }));
  const toggleGroup = (id: string) => setGroupsExpanded(prev => ({ ...prev, [id]: !prev[id] }));

  const handlePin = useCallback((item: ResourceItem) => {
    setPinnedItems(prev => prev.some(i => i.id === item.id) ? prev : [item, ...prev]);
  }, []);

  const handleUnpin = useCallback((itemId: string) => {
    setPinnedItems(prev => prev.filter(i => i.id !== itemId));
  }, []);

  // 过滤当前已打开的 Tab (排除管理项)
  const activeOpenedTabs = useMemo(() => {
    return tabs.filter(t => t.id !== 'elements-view' && t.id !== 'default-home');
  }, [tabs]);

  // 搜索过滤
  const filteredHistory = useMemo(() => {
    const q = searchQuery.toLowerCase();
    if (!q) return historyItems;
    return historyItems.filter(h => h.name.toLowerCase().includes(q) || (h.code && h.code.toLowerCase().includes(q)));
  }, [searchQuery, historyItems]);

  const filteredPinned = useMemo(() => {
    const q = searchQuery.toLowerCase();
    if (!q) return pinnedItems;
    return pinnedItems.filter(p => p.name.toLowerCase().includes(q) || (p.code && p.code.toLowerCase().includes(q)));
  }, [searchQuery, pinnedItems]);

  const [lockedDrawerType, setLockedDrawerType] = useState<ModuleId | null>(activeDrawerType || null);
  useEffect(() => {
    if (activeDrawerType) setLockedDrawerType(activeDrawerType);
  }, [activeDrawerType]);

  const currentTree = useMemo(() => {
    const data = isUserMode ? (MODULE_DATA[activeModule] || []) : (MODULE_DATA[selectedModule] || MODULE_DATA['all'] || []);
    if (!searchQuery) return data;
    const lowerQuery = searchQuery.toLowerCase();
    return data.map(dir => ({
      ...dir,
      children: dir.children?.filter(item => 
        item.name.toLowerCase().includes(lowerQuery) || (item.code && item.code.toLowerCase().includes(lowerQuery))
      )
    })).filter(dir => (dir.children && dir.children.length > 0) || dir.name.toLowerCase().includes(lowerQuery));
  }, [selectedModule, activeModule, searchQuery, isUserMode]);

  return (
    <div className="flex flex-col h-full bg-white select-none relative border-r border-slate-100">
      <div className="h-14 flex items-center px-4 justify-between border-b border-slate-100 bg-white shrink-0">
        <div className="flex items-center gap-2">
          <span className="font-bold text-slate-800 tracking-tight text-[13px] uppercase">
            {activeModule === 'recent_fav' ? '最近打开' : (isUserMode ? '业务模块' : '资源管理')}
          </span>
        </div>
        <div className="flex items-center gap-1">
          <button onClick={() => setShowCode(!showCode)} className={`p-1.5 rounded transition-all active:scale-90 ${showCode ? 'bg-blue-600 text-white shadow-sm' : 'text-slate-400 hover:bg-slate-50'}`}>
            {showCode ? <Code2 size={14} /> : <Eye size={14} />}
          </button>
          <button onClick={onToggleCollapse} className="p-1.5 text-slate-400 hover:bg-slate-50 rounded transition-colors">
            <PanelLeftClose size={14} />
          </button>
        </div>
      </div>

      <div className="flex-1 flex flex-col min-h-0 overflow-hidden">
        <div className="p-2 space-y-3">
          <div className="relative">
            <Search className="absolute left-2.5 top-1/2 -translate-y-1/2 text-slate-400" size={13} />
            <input type="text" placeholder="搜索资源..." value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)} className="w-full bg-slate-50 border border-slate-200 rounded py-1.5 pl-8 pr-3 text-[12px] outline-none focus:border-blue-500 focus:bg-white transition-all shadow-sm" />
          </div>
        </div>

        <div className="flex-1 overflow-y-auto px-1 no-scrollbar pb-10">
          {activeModule === 'recent_fav' ? (
            <div className="space-y-6 pt-1">

              {/* 1. 常用 (Pinned Items) - 放置在最上方 */}
              <div className="px-1">
                <button onClick={() => toggleGroup('fav')} className="w-full flex items-center justify-between p-1.5 mb-1 text-slate-400 bg-slate-50/50 rounded hover:bg-slate-100/50 transition-colors">
                  <div className="flex items-center gap-2">
                    <Star size={14} className="text-amber-500 fill-amber-500/20" />
                    <span className="text-[11px] font-black uppercase tracking-widest">常用</span>
                  </div>
                  {groupsExpanded.fav ? <ChevronDown size={12} /> : <ChevronRight size={12} />}
                </button>
                {groupsExpanded.fav && (
                  <div className="space-y-0.5 animate-in fade-in slide-in-from-top-1 duration-200">
                    {filteredPinned.length > 0 ? filteredPinned.map(item => {
                      const isOpen = tabs.some(t => t.id === item.id);
                      const isActive = activeTab?.id === item.id;
                      return (
                        <div key={item.id} onClick={() => onSelectResource(item)} className={`flex items-center gap-2 p-1.5 rounded cursor-pointer group transition-all ${isActive ? 'bg-blue-600/5 shadow-inner' : 'hover:bg-blue-50/50'}`}>
                          {getIconForType(item.type)}
                          <span className={`text-[12px] truncate flex-1 transition-all ${isActive ? 'text-blue-600 font-bold' : (isOpen ? 'text-slate-700' : 'text-slate-500')}`}>
                            {showCode ? item.code : item.name}
                          </span>
                          {isOpen && !isActive && <div className="w-1.5 h-1.5 bg-blue-500 rounded-full opacity-50"></div>}
                          <button className="opacity-0 group-hover:opacity-100 p-1 text-slate-300 hover:text-blue-600 hover:bg-blue-50 rounded" onClick={(e) => { e.stopPropagation(); handleUnpin(item.id); }}>
                            <PinOff size={12} />
                          </button>
                        </div>
                      );
                    }) : <div className="p-3 text-[11px] text-slate-300 text-center italic">暂无常用项</div>}
                  </div>
                )}
              </div>

              {/* 2. 最近 (Merged: Opened + History) */}
              <div className="px-1">
                <button onClick={() => toggleGroup('recent')} className="w-full flex items-center justify-between p-1.5 mb-1 text-slate-400 bg-slate-50/50 rounded hover:bg-slate-100/50 transition-colors">
                  <div className="flex items-center gap-2">
                    <Clock size={14} className="text-blue-600" />
                    <span className="text-[11px] font-black uppercase tracking-widest">最近</span>
                    {(activeOpenedTabs.length + filteredHistory.length) > 0 && (
                      <span className="bg-slate-200 text-slate-500 px-1 rounded text-[9px] font-bold">
                        {activeOpenedTabs.length + filteredHistory.length}
                      </span>
                    )}
                  </div>
                  {groupsExpanded.recent ? <ChevronDown size={12} /> : <ChevronRight size={12} />}
                </button>

                {groupsExpanded.recent && (
                  <div className="space-y-0.5 animate-in fade-in slide-in-from-top-1 duration-200">

                    {/* A. 正在打开的 Tab */}
                    {activeOpenedTabs.map(item => (
                      <div key={item.id} onClick={() => onSelectResource({ id: item.id, name: item.title, type: item.type, code: item.code })} className={`flex items-center gap-2 p-1.5 rounded cursor-pointer group transition-all ${activeTab?.id === item.id ? 'bg-blue-600/5 shadow-inner' : 'hover:bg-blue-50/50'}`}>
                        {getIconForType(item.type as ResourceType)}
                        <span className={`text-[12px] truncate flex-1 transition-all ${activeTab?.id === item.id ? 'text-blue-600 font-bold' : 'text-slate-700 font-medium'}`}>
                          {showCode ? (item.code || item.title) : item.title}
                        </span>
                        <button onClick={(e) => { e.stopPropagation(); onCloseTab(item.id); }} className="opacity-0 group-hover:opacity-100 p-1 text-slate-300 hover:text-rose-500 rounded hover:bg-rose-50 transition-all">
                          <X size={12} />
                        </button>
                      </div>
                    ))}

                    {/* 分割线 - 只有当两部分都有内容时更有意义 */}
                    {(activeOpenedTabs.length > 0 && filteredHistory.length > 0) && (
                      <div className="flex items-center gap-2 py-2 px-1 opacity-40">
                        <div className="flex-1 h-[1px] bg-slate-200"></div>
                        <span className="text-[9px] font-black text-slate-300 uppercase tracking-widest">最近关闭</span>
                        <div className="flex-1 h-[1px] bg-slate-200"></div>
                      </div>
                    )}

                    {/* B. 历史记录部分 (灰色) */}
                    {filteredHistory.map(item => {
                      const isPinned = pinnedItems.some(p => p.id === item.id);
                      return (
                        <div key={item.id} onClick={() => onSelectResource(item)} className="flex items-center gap-2 p-1.5 rounded cursor-pointer group hover:bg-slate-50 transition-colors">
                          <div className="opacity-30 grayscale shrink-0">{getIconForType(item.type)}</div>
                          <span className={`text-[12px] truncate flex-1 text-slate-400 group-hover:text-slate-500 transition-colors`}>
                            {showCode ? item.code : item.name}
                          </span>
                          <button 
                            className={`p-1 rounded transition-all ${isPinned ? 'text-blue-600 opacity-40' : 'opacity-0 group-hover:opacity-100 text-slate-300 hover:text-blue-600 hover:bg-blue-50'}`}
                            onClick={(e) => { e.stopPropagation(); if (!isPinned) handlePin(item); }}
                          >
                            <Pin size={12} fill={isPinned ? "currentColor" : "none"} />
                          </button>
                        </div>
                      );
                    })}

                    {activeOpenedTabs.length === 0 && filteredHistory.length === 0 && (
                      <div className="p-4 text-[11px] text-slate-300 text-center">暂无活动记录</div>
                    )}
                  </div>
                )}
              </div>

            </div>
          ) : (
            currentTree.map(dir => (
              <div key={dir.id} className="mb-0.5">
                <div onClick={() => toggleExpand(dir.id)} className="flex items-center gap-2 p-1.5 hover:bg-slate-100/60 rounded cursor-pointer group">
                  <div className="w-4 h-4 flex items-center justify-center shrink-0">
                    {expanded[dir.id] ? <ChevronDown size={12} className="text-slate-400" /> : <ChevronRight size={12} className="text-slate-400" />}
                  </div>
                  {getIconForType('folder')}
                  <span className="text-[12px] font-medium text-slate-600 truncate">{showCode ? dir.code : dir.name}</span>
                </div>
                {expanded[dir.id] && dir.children && (
                  <div className="ml-5 border-l border-slate-100 mt-0.5 mb-1">
                    {dir.children.map(item => (
                      <div key={item.id} onClick={() => onSelectResource(item)} className="flex items-center gap-2 p-1.5 pl-4 hover:bg-blue-50/50 rounded cursor-pointer group relative">
                        {getIconForType(item.type)}
                        <span className={`text-[12px] truncate flex-1 transition-colors ${activeTab?.id === item.id ? 'text-blue-600 font-bold' : 'text-slate-500'}`}>
                          {showCode ? item.code : item.name}
                        </span>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            ))
          )}
        </div>
      </div>

      <div style={{ height: showContext ? `${contextHeight}px` : '0px', opacity: showContext ? 1 : 0 }} className="border-t border-slate-200 bg-slate-50/80 flex flex-col shrink-0 relative transition-all duration-300 ease-in-out overflow-hidden z-10">
        <div onMouseDown={() => setIsResizingContext(true)} className="absolute top-0 left-0 w-full h-1 cursor-row-resize hover:bg-blue-400/30 z-50 active:bg-blue-500" />
        <div className="h-9 flex items-center px-3 justify-between border-b border-slate-200 bg-white">
          <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-2">
            {lockedDrawerType === 'console' ? <><Terminal size={12} className="text-blue-600" /> 控制台</> : <><Info size={12} className="text-blue-600" /> 元素信息</>}
          </span>
          <button onClick={onCloseContext} className="p-1 hover:bg-slate-100 rounded text-slate-400"><ChevronDown size={14} /></button>
        </div>
        <div className="flex-1 overflow-y-auto p-3 no-scrollbar space-y-4">
          {lockedDrawerType === 'console' ? (
            <div className="grid grid-cols-1 gap-1">
              {CONSOLE_ITEMS.map(item => (
                <button key={item.id} onClick={() => onSelectResource({ id: item.id, name: item.name, type: 'page' })} className="flex items-center gap-3 p-2 rounded-lg text-[12px] text-slate-600 bg-white border border-slate-100 hover:border-blue-300 hover:bg-blue-50/30 hover:text-blue-600 transition-all text-left shadow-sm group">
                  <span className="shrink-0 transition-transform group-hover:scale-110">{item.icon}</span>
                  <span className="truncate flex-1 font-medium">{item.name}</span>
                </button>
              ))}
            </div>
          ) : activeTab ? (
            <>
              <div className="bg-white p-2.5 rounded-lg border border-slate-200 shadow-sm space-y-1.5">
                <div className="flex items-center gap-2 text-[12px] font-bold text-slate-800">{activeTab.title}</div>
                <div className="text-[10px] text-slate-400 font-mono">{activeTab.code}</div>
              </div>
              <section className="space-y-1.5">
                <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-1.5"><HistoryIcon size={10} className="text-blue-600" /> 修改信息</h4>
                <div className="bg-white/50 border border-slate-100 rounded-lg p-2 text-[11px] space-y-1">
                  <div className="flex justify-between"><span className="text-slate-500">更新人:</span><span className="text-blue-600 font-bold">liuqing</span></div>
                  <div className="flex justify-between"><span className="text-slate-500">更新时间:</span><span className="text-slate-400">{activeTab.updatedAt || '刚刚'}</span></div>
                </div>
              </section>
            </>
          ) : (
            <div className="h-full flex flex-col items-center justify-center opacity-30 grayscale p-4">
              <Info size={32} className="mb-2" />
              <p className="text-[10px] font-bold uppercase tracking-widest">未选择元素</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default Explorer;

import React, { useState, useMemo, useCallback, useEffect, useRef } from 'react';
import { 
  ChevronDown, 
  ChevronRight, 
  Search,
  FolderOpen,
  FileText,
  Database,
  Workflow,
  Cpu,
  Code2,
  Eye,
  X,
  Star,
  Layout,
  Clock,
  Activity,
  ListTodo,
  PanelLeftClose,
  Terminal,
  Info,
  Pin,
  PinOff,
  History as HistoryIcon,
  // Added Grid3X3 to fix the missing import error
  Grid3X3
} from 'lucide-react';
import { ModuleId, ResourceItem, Tab, ResourceType } from '../types';

interface ExplorerProps {
  activeModule: ModuleId;
  onSelectResource: (item: any) => void;
  isUserMode?: boolean;
  activeTab?: Tab;
  tabs: Tab[];
  onCloseTab: (id: string) => void;
  showContext?: boolean;
  activeDrawerType?: ModuleId | null;
  onCloseContext?: () => void;
  onToggleCollapse?: () => void;
}

const MODULE_DATA: Record<string, ResourceItem[]> = {
  'module-ux': [
    { id: 'dir_ux_1', name: '电子表格', code: 'DIR_SPREADSHEET', type: 'folder', version: '', createdBy: '', updatedAt: '', children: [
      { id: 'res_ux_1', name: '年度预算录入表', code: 'BUDGET_SHEET', type: 'spreadsheet', version: '1.0', createdBy: 'liuqing', updatedAt: '2025-05-10' },
      { id: 'res_ux_2', name: '费用报销明细', code: 'EXPENSE_DETAIL', type: 'spreadsheet', version: '2.1', createdBy: 'admin', updatedAt: '2025-05-11' },
    ]},
    { id: 'dir_ux_2', name: 'UX 页面', code: 'DIR_UX_PAGE', type: 'folder', version: '', createdBy: '', updatedAt: '', children: [
      { id: 'res_ux_3', name: '财务看板-主视图', code: 'FIN_DASHBOARD', type: 'ux', version: '1.0', createdBy: 'liuqing', updatedAt: '2025-05-12' },
    ]}
  ],
  'finance_center': [
    { id: 'root_statement', name: '财务报表', code: 'ROOT_FIN_STMT', type: 'folder', version: '', createdBy: '', updatedAt: '', children: [
      { id: 'res_stmt_1', name: '合并资产负债表', code: 'CONSOL_BS', type: 'spreadsheet', version: '1.0', createdBy: 'liuqing', updatedAt: '2025-05-15' },
    ]},
  ],
  'all': [
    { id: 'root_ux', name: '01 页面展现', code: 'ROOT_UX', type: 'folder', version: '', createdBy: '', updatedAt: '', children: [
      { id: 'res_ux_1', name: '年度预算录入表', code: 'BUDGET_SHEET', type: 'spreadsheet', version: '1.0', createdBy: 'liuqing', updatedAt: '2025-05-10' },
    ]},
    { id: 'root_model', name: '02 数据模型', code: 'ROOT_MODEL', type: 'folder', version: '', createdBy: '', updatedAt: '', children: [
      { id: 'res_m_1', name: '对账核销核心模型', code: 'MODEL_RECON_CORE', type: 'model', version: '3.0', createdBy: 'liuqing', updatedAt: '2025-05-14' },
    ]},
  ]
};

const INITIAL_FAVORITE_ITEMS: ResourceItem[] = [
  { id: 'res_ux_1', name: '年度预算录入表', code: 'BUDGET_SHEET', type: 'spreadsheet', version: '1.0', createdBy: 'liuqing', updatedAt: '2025-05-10' },
];

const INITIAL_HISTORY_ITEMS: ResourceItem[] = [
  { id: 'res_ux_comp_1', name: '利润分配逻辑表', code: 'PROFIT_DIST', type: 'spreadsheet', version: '1.0', createdBy: 'liuqing', updatedAt: '2025-05-12' },
  { id: 'res_l_1', name: '月度折旧计提逻辑', code: 'DEPRECIATION_LOGIC', type: 'script', version: '1.0', createdBy: 'liuqing', updatedAt: '2025-05-24' },
];

const CONSOLE_ITEMS = [
  { id: 'c1', name: '执行记录', icon: <Activity size={14} /> },
  { id: 'c2', name: '系统日志', icon: <Terminal size={14} /> },
];

const getIconForType = (type: ResourceType) => {
  switch (type) {
    case 'folder': return <FolderOpen size={14} className="text-amber-500 fill-amber-500/10" />;
    case 'model': return <Database size={14} className="text-purple-500" />;
    case 'logic': return <Workflow size={14} className="text-sky-500" />;
    case 'workflow': return <Cpu size={14} className="text-indigo-500" />;
    case 'spreadsheet': return <Grid3X3 size={14} className="text-emerald-500" />;
    case 'ux': return <Layout size={14} className="text-blue-500" />;
    case 'accounting': return <HistoryIcon size={14} className="text-rose-500" />;
    case 'script': return <Terminal size={14} className="text-slate-500" />;
    default: return <FileText size={14} className="text-slate-400" />;
  }
};

const Explorer: React.FC<ExplorerProps> = ({ 
  activeModule,
  onSelectResource, 
  isUserMode, 
  activeTab,
  tabs,
  onCloseTab,
  showContext = true,
  activeDrawerType,
  onCloseContext,
  onToggleCollapse
}) => {
  const [selectedModule, setSelectedModule] = useState(isUserMode ? activeModule : 'all');
  const [expanded, setExpanded] = useState<Record<string, boolean>>({ 'root_ux': true, 'root_model': true });
  const [groupsExpanded, setGroupsExpanded] = useState<Record<string, boolean>>({
    recent: true,
    fav: true
  });
  const [showCode, setShowCode] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [contextHeight, setContextHeight] = useState(320);
  const [isResizingContext, setIsResizingContext] = useState(false);

  // 历史记录与常用项状态
  const [historyItems, setHistoryItems] = useState<ResourceItem[]>(INITIAL_HISTORY_ITEMS);
  const [pinnedItems, setPinnedItems] = useState<ResourceItem[]>(INITIAL_FAVORITE_ITEMS);

  // 追踪 Tabs 变化以管理历史
  const prevTabsRef = useRef<Tab[]>(tabs);

  useEffect(() => {
    const prevTabs = prevTabsRef.current;

    // 1. 查找被关闭的 Tab
    const closedTabs = prevTabs.filter(prev => !tabs.some(curr => curr.id === prev.id));
    if (closedTabs.length > 0) {
      setHistoryItems(prev => {
        let newHistory = [...prev];
        closedTabs.forEach(closed => {
          // 排除非资源的固有管理视图
          if (closed.id === 'elements-view' || closed.id === 'default-home') return;

          // 移除历史中重复的项，并将最新关闭的移到最上方
          newHistory = newHistory.filter(h => h.id !== closed.id);
          const historyEntry: ResourceItem = {
            id: closed.id,
            name: closed.title,
            code: closed.code || '',
            type: closed.type as any,
            version: '1.0',
            createdBy: 'system',
            updatedAt: new Date().toISOString()
          };
          newHistory = [historyEntry, ...newHistory];
        });
        // 限制最多 10 条历史
        return newHistory.slice(0, 10);
      });
    }

    // 2. 查找新开启的 Tab (如果该项在历史中，则移除它)
    const openedTabs = tabs.filter(curr => !prevTabs.some(prev => prev.id === curr.id));
    if (openedTabs.length > 0) {
      setHistoryItems(prev => prev.filter(h => !openedTabs.some(o => o.id === h.id)));
    }

    prevTabsRef.current = tabs;
  }, [tabs]);

  const toggleExpand = (id: string) => setExpanded(prev => ({ ...prev, [id]: !prev[id] }));
  const toggleGroup = (id: string) => setGroupsExpanded(prev => ({ ...prev, [id]: !prev[id] }));

  const handlePin = useCallback((item: ResourceItem) => {
    setPinnedItems(prev => prev.some(i => i.id === item.id) ? prev : [item, ...prev]);
  }, []);

  const handlePinAction = (e: React.MouseEvent, item: ResourceItem) => {
    e.stopPropagation();
    handlePin(item);
  };

  const handleUnpin = useCallback((itemId: string) => {
    setPinnedItems(prev => prev.filter(i => i.id !== itemId));
  }, []);

  // 过滤当前已打开的 Tab (排除管理项)
  const activeOpenedTabs = useMemo(() => {
    return tabs.filter(t => t.id !== 'elements-view' && t.id !== 'default-home');
  }, [tabs]);

  // 搜索过滤
  const filteredHistory = useMemo(() => {
    const q = searchQuery.toLowerCase();
    if (!q) return historyItems;
    return historyItems.filter(h => h.name.toLowerCase().includes(q) || (h.code && h.code.toLowerCase().includes(q)));
  }, [searchQuery, historyItems]);

  const filteredPinned = useMemo(() => {
    const q = searchQuery.toLowerCase();
    if (!q) return pinnedItems;
    return pinnedItems.filter(p => p.name.toLowerCase().includes(q) || (p.code && p.code.toLowerCase().includes(q)));
  }, [searchQuery, pinnedItems]);

  const [lockedDrawerType, setLockedDrawerType] = useState<ModuleId | null>(activeDrawerType || null);
  useEffect(() => {
    if (activeDrawerType) setLockedDrawerType(activeDrawerType);
  }, [activeDrawerType]);

  const currentTree = useMemo(() => {
    const data = isUserMode ? (MODULE_DATA[activeModule] || []) : (MODULE_DATA[selectedModule] || MODULE_DATA['all'] || []);
    if (!searchQuery) return data;
    const lowerQuery = searchQuery.toLowerCase();
    return data.map(dir => ({
      ...dir,
      children: dir.children?.filter(item => 
        item.name.toLowerCase().includes(lowerQuery) || (item.code && item.code.toLowerCase().includes(lowerQuery))
      )
    })).filter(dir => (dir.children && dir.children.length > 0) || dir.name.toLowerCase().includes(lowerQuery));
  }, [selectedModule, activeModule, searchQuery, isUserMode]);

  return (
    <div className="flex flex-col h-full bg-white select-none relative border-r border-slate-100">
      <div className="h-14 flex items-center px-4 justify-between border-b border-slate-100 bg-white shrink-0">
        <div className="flex items-center gap-2">
          <span className="font-bold text-slate-800 tracking-tight text-[13px] uppercase">
            {activeModule === 'recent_fav' ? '最近打开' : (isUserMode ? '业务模块' : '资源管理')}
          </span>
        </div>
        <div className="flex items-center gap-1">
          <button onClick={() => setShowCode(!showCode)} className={`p-1.5 rounded transition-all active:scale-90 ${showCode ? 'bg-blue-600 text-white shadow-sm' : 'text-slate-400 hover:bg-slate-50'}`}>
            {showCode ? <Code2 size={14} /> : <Eye size={14} />}
          </button>
          <button onClick={onToggleCollapse} className="p-1.5 text-slate-400 hover:bg-slate-50 rounded transition-colors">
            <PanelLeftClose size={14} />
          </button>
        </div>
      </div>

      <div className="flex-1 flex flex-col min-h-0 overflow-hidden">
        <div className="p-2 space-y-3">
          <div className="relative">
            <Search className="absolute left-2.5 top-1/2 -translate-y-1/2 text-slate-400" size={13} />
            <input type="text" placeholder="搜索资源..." value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)} className="w-full bg-slate-50 border border-slate-200 rounded py-1.5 pl-8 pr-3 text-[12px] outline-none focus:border-blue-500 focus:bg-white transition-all shadow-sm" />
          </div>
        </div>

        <div className="flex-1 overflow-y-auto px-1 no-scrollbar pb-10">
          {activeModule === 'recent_fav' ? (
            <div className="space-y-6 pt-1">

              {/* 1. 常用 (Pinned Items) - 放置在最上方 */}
              <div className="px-1">
                <button onClick={() => toggleGroup('fav')} className="w-full flex items-center justify-between p-1.5 mb-1 text-slate-400 bg-slate-50/50 rounded hover:bg-slate-100/50 transition-colors">
                  <div className="flex items-center gap-2">
                    <Star size={14} className="text-amber-500 fill-amber-500/20" />
                    <span className="text-[11px] font-black uppercase tracking-widest">常用</span>
                  </div>
                  {groupsExpanded.fav ? <ChevronDown size={12} /> : <ChevronRight size={12} />}
                </button>
                {groupsExpanded.fav && (
                  <div className="space-y-0.5 animate-in fade-in slide-in-from-top-1 duration-200">
                    {filteredPinned.length > 0 ? filteredPinned.map(item => {
                      const isOpen = tabs.some(t => t.id === item.id);
                      const isActive = activeTab?.id === item.id;
                      return (
                        <div key={item.id} onClick={() => onSelectResource(item)} className={`flex items-center gap-2 p-1.5 rounded cursor-pointer group transition-all ${isActive ? 'bg-blue-600/5 shadow-inner' : 'hover:bg-blue-50/50'}`}>
                          {getIconForType(item.type)}
                          <span className={`text-[12px] truncate flex-1 transition-all ${isActive ? 'text-blue-600 font-bold' : (isOpen ? 'text-slate-700' : 'text-slate-500')}`}>
                            {showCode ? item.code : item.name}
                          </span>
                          {isOpen && !isActive && <div className="w-1.5 h-1.5 bg-blue-500 rounded-full opacity-50"></div>}
                          <button className="opacity-0 group-hover:opacity-100 p-1 text-slate-300 hover:text-blue-600 hover:bg-blue-50 rounded" onClick={(e) => { e.stopPropagation(); handleUnpin(item.id); }}>
                            <PinOff size={12} />
                          </button>
                        </div>
                      );
                    }) : <div className="p-3 text-[11px] text-slate-300 text-center italic">暂无常用项</div>}
                  </div>
                )}
              </div>

              {/* 2. 最近 (Merged: Opened + History) */}
              <div className="px-1">
                <button onClick={() => toggleGroup('recent')} className="w-full flex items-center justify-between p-1.5 mb-1 text-slate-400 bg-slate-50/50 rounded hover:bg-slate-100/50 transition-colors">
                  <div className="flex items-center gap-2">
                    <Clock size={14} className="text-blue-600" />
                    <span className="text-[11px] font-black uppercase tracking-widest">最近</span>
                    {(activeOpenedTabs.length + filteredHistory.length) > 0 && (
                      <span className="bg-slate-200 text-slate-500 px-1 rounded text-[9px] font-bold">
                        {activeOpenedTabs.length + filteredHistory.length}
                      </span>
                    )}
                  </div>
                  {groupsExpanded.recent ? <ChevronDown size={12} /> : <ChevronRight size={12} />}
                </button>

                {groupsExpanded.recent && (
                  <div className="space-y-0.5 animate-in fade-in slide-in-from-top-1 duration-200">

                    {/* A. 正在打开的 Tab */}
                    {activeOpenedTabs.map(item => (
                      <div key={item.id} onClick={() => onSelectResource({ id: item.id, name: item.title, type: item.type, code: item.code })} className={`flex items-center gap-2 p-1.5 rounded cursor-pointer group transition-all ${activeTab?.id === item.id ? 'bg-blue-600/5 shadow-inner' : 'hover:bg-blue-50/50'}`}>
                        {getIconForType(item.type as ResourceType)}
                        <span className={`text-[12px] truncate flex-1 transition-all ${activeTab?.id === item.id ? 'text-blue-600 font-bold' : 'text-slate-700 font-medium'}`}>
                          {showCode ? (item.code || item.title) : item.title}
                        </span>
                        <button onClick={(e) => { e.stopPropagation(); onCloseTab(item.id); }} className="opacity-0 group-hover:opacity-100 p-1 text-slate-300 hover:text-rose-500 rounded hover:bg-rose-50 transition-all">
                          <X size={12} />
                        </button>
                      </div>
                    ))}

                    {/* 分割线 - 只有当两部分都有内容时更有意义 */}
                    {(activeOpenedTabs.length > 0 && filteredHistory.length > 0) && (
                      <div className="flex items-center gap-2 py-2 px-1 opacity-40">
                        <div className="flex-1 h-[1px] bg-slate-200"></div>
                        <span className="text-[9px] font-black text-slate-300 uppercase tracking-widest">最近关闭</span>
                        <div className="flex-1 h-[1px] bg-slate-200"></div>
                      </div>
                    )}

                    {/* B. 历史记录部分 (灰色) */}
                    {filteredHistory.map(item => {
                      const isPinned = pinnedItems.some(p => p.id === item.id);
                      return (
                        <div key={item.id} onClick={() => onSelectResource(item)} className="flex items-center gap-2 p-1.5 rounded cursor-pointer group hover:bg-slate-50 transition-colors">
                          <div className="opacity-30 grayscale shrink-0">{getIconForType(item.type)}</div>
                          <span className={`text-[12px] truncate flex-1 text-slate-400 group-hover:text-slate-500 transition-colors`}>
                            {showCode ? item.code : item.name}
                          </span>
                          <button 
                            className={`p-1 rounded transition-all ${isPinned ? 'text-blue-600 opacity-40' : 'opacity-0 group-hover:opacity-100 text-slate-300 hover:text-blue-600 hover:bg-blue-50'}`}
                            onClick={(e) => { if (!isPinned) handlePinAction(e, item); }}
                          >
                            <Pin size={12} fill={isPinned ? "currentColor" : "none"} />
                          </button>
                        </div>
                      );
                    })}

                    {activeOpenedTabs.length === 0 && filteredHistory.length === 0 && (
                      <div className="p-4 text-[11px] text-slate-300 text-center">暂无活动记录</div>
                    )}
                  </div>
                )}
              </div>

            </div>
          ) : (
            currentTree.map(dir => (
              <div key={dir.id} className="mb-0.5">
                <div onClick={() => toggleExpand(dir.id)} className="flex items-center gap-2 p-1.5 hover:bg-slate-100/60 rounded cursor-pointer group">
                  <div className="w-4 h-4 flex items-center justify-center shrink-0">
                    {expanded[dir.id] ? <ChevronDown size={12} className="text-slate-400" /> : <ChevronRight size={12} className="text-slate-400" />}
                  </div>
                  {getIconForType('folder')}
                  <span className="text-[12px] font-medium text-slate-600 truncate">{showCode ? dir.code : dir.name}</span>
                </div>
                {expanded[dir.id] && dir.children && (
                  <div className="ml-5 border-l border-slate-100 mt-0.5 mb-1">
                    {dir.children.map(item => (
                      <div key={item.id} onClick={() => onSelectResource(item)} className="flex items-center gap-2 p-1.5 pl-4 hover:bg-blue-50/50 rounded cursor-pointer group relative">
                        {getIconForType(item.type)}
                        <span className={`text-[12px] truncate flex-1 transition-colors ${activeTab?.id === item.id ? 'text-blue-600 font-bold' : 'text-slate-500'}`}>
                          {showCode ? item.code : item.name}
                        </span>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            ))
          )}
        </div>
      </div>

      <div style={{ height: showContext ? `${contextHeight}px` : '0px', opacity: showContext ? 1 : 0 }} className="border-t border-slate-200 bg-slate-50/80 flex flex-col shrink-0 relative transition-all duration-300 ease-in-out overflow-hidden z-10">
        <div onMouseDown={() => setIsResizingContext(true)} className="absolute top-0 left-0 w-full h-1 cursor-row-resize hover:bg-blue-400/30 z-50 active:bg-blue-500" />
        <div className="h-9 flex items-center px-3 justify-between border-b border-slate-200 bg-white">
          <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-2">
            {lockedDrawerType === 'console' ? <><Terminal size={12} className="text-blue-600" /> 控制台</> : <><Info size={12} className="text-blue-600" /> 元素信息</>}
          </span>
          <button onClick={onCloseContext} className="p-1 hover:bg-slate-100 rounded text-slate-400"><ChevronDown size={14} /></button>
        </div>
        <div className="flex-1 overflow-y-auto p-3 no-scrollbar space-y-4">
          {lockedDrawerType === 'console' ? (
            <div className="grid grid-cols-1 gap-1">
              {CONSOLE_ITEMS.map(item => (
                <button key={item.id} onClick={() => onSelectResource({ id: item.id, name: item.name, type: 'page' })} className="flex items-center gap-3 p-2 rounded-lg text-[12px] text-slate-600 bg-white border border-slate-100 hover:border-blue-300 hover:bg-blue-50/30 hover:text-blue-600 transition-all text-left shadow-sm group">
                  <span className="shrink-0 transition-transform group-hover:scale-110">{item.icon}</span>
                  <span className="truncate flex-1 font-medium">{item.name}</span>
                </button>
              ))}
            </div>
          ) : activeTab ? (
            <>
              <div className="bg-white p-2.5 rounded-lg border border-slate-200 shadow-sm space-y-1.5">
                <div className="flex items-center gap-2 text-[12px] font-bold text-slate-800">{activeTab.title}</div>
                <div className="text-[10px] text-slate-400 font-mono">{activeTab.code}</div>
              </div>
              <section className="space-y-1.5">
                <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-1.5"><HistoryIcon size={10} className="text-blue-600" /> 修改信息</h4>
                <div className="bg-white/50 border border-slate-100 rounded-lg p-2 text-[11px] space-y-1">
                  <div className="flex justify-between"><span className="text-slate-500">更新人:</span><span className="text-blue-600 font-bold">liuqing</span></div>
                  <div className="flex justify-between"><span className="text-slate-500">更新时间:</span><span className="text-slate-400">{activeTab.updatedAt || '刚刚'}</span></div>
                </div>
              </section>
            </>
          ) : (
            <div className="h-full flex flex-col items-center justify-center opacity-30 grayscale p-4">
              <Info size={32} className="mb-2" />
              <p className="text-[10px] font-bold uppercase tracking-widest">未选择元素</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default Explorer;

import React, { useState, useMemo, useCallback, useEffect, useRef } from 'react';
import { 
  ChevronDown, 
  ChevronRight, 
  Search,
  FolderOpen,
  FileText,
  Database,
  Workflow,
  Cpu,
  Code2,
  Eye,
  X,
  Star,
  Layout,
  Clock,
  Activity,
  ListTodo,
  PanelLeftClose,
  Terminal,
  Info,
  Pin,
  PinOff,
  History as HistoryIcon,
  Grid3X3,
  Filter,
  Plus,
  MoreHorizontal,
  Link,
  ArrowRightLeft,
  Zap,
  ShieldCheck,
  TableProperties
} from 'lucide-react';
import { ModuleId, ResourceItem, Tab, ResourceType } from '../types';

interface ExplorerProps {
  activeModule: ModuleId;
  onSelectResource: (item: any) => void;
  isUserMode?: boolean;
  activeTab?: Tab;
  tabs: Tab[];
  onCloseTab: (id: string) => void;
  showContext?: boolean;
  activeDrawerType?: ModuleId | null;
  onCloseContext?: () => void;
  onToggleCollapse?: () => void;
}

